    $$question$$,
    $$Which amide local anesthetic is distinctive in being partly hydrolyzed by plasma esterases, giving
it a shorter plasma half-life than the other amides?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — articaine pharmacology$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$articaine$$, true, NULL, 0),
    (qid, $$B$$, $$lidocaine$$, false, $$Lidocaine is metabolized in the liver, not by plasma esterases.$$, 1),
    (qid, $$C$$, $$mepivacaine$$, false, $$Mepivacaine is also hepatically metabolized.$$, 2),
    (qid, $$D$$, $$bupivacaine$$, false, $$Bupivacaine is hepatically metabolized and is long-acting, the opposite of a short plasma half-life.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Articaine contains a thiophene ring and, unlike other amides, an additional ester side chain. That
ester is rapidly hydrolyzed by plasma cholinesterase, so a large fraction is inactivated in the
blood and its plasma half-life is only about 20-30 minutes, lowering the risk of systemic
accumulation.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
