    $$question$$,
    $$Exceeding the maximum dose of which local anesthetic is most likely to precipitate
methemoglobinemia?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — prilocaine and methemoglobinemia$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$prilocaine$$, true, NULL, 0),
    (qid, $$B$$, $$lidocaine$$, false, $$Lidocaine is not a notable cause of methemoglobinemia at clinical doses.$$, 1),
    (qid, $$C$$, $$mepivacaine$$, false, $$Mepivacaine does not carry a meaningful methemoglobinemia risk.$$, 2),
    (qid, $$D$$, $$bupivacaine$$, false, $$Bupivacaine is not associated with methemoglobinemia.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Prilocaine is metabolized to o-toluidine, which oxidizes the iron in hemoglobin from the ferrous to
the ferric state, forming methemoglobin that cannot carry oxygen. At high doses this can produce
clinically significant methemoglobinemia (cyanosis unresponsive to oxygen). Topical benzocaine is
another well-known cause.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

