    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$uncharged base that diffuses across the nerve membrane$$, true, NULL, 0),
    (qid, $$B$$, $$charged cation that remains outside the nerve$$, false, $$The charged cation cannot cross the membrane; although it is the form that ultimately blocks the sodium channel from inside, its extracellular abundance slows, not speeds, diffusion.$$, 1),
    (qid, $$C$$, $$protein-bound fraction circulating in plasma$$, false, $$Protein binding correlates with duration of action, not speed of onset.$$, 2),
    (qid, $$D$$, $$inactive metabolite produced in the liver$$, false, $$Hepatic metabolites are inactive and unrelated to onset.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Onset depends on how much anesthetic can cross the lipid nerve membrane. Only the uncharged
(nonionized) base is lipid-soluble enough to diffuse through; the closer the pKa is to tissue pH,
the larger that base fraction, so onset is faster. Once inside the axon, the molecule re-equilibrates
and it is the charged cation that binds the sodium channel to block conduction.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
