    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$increase heart rate and myocardial oxygen demand$$, true, NULL, 0),
    (qid, $$B$$, $$provoke an immediate IgE-mediated allergic reaction$$, false, $$Epinephrine is identical to an endogenous hormone and does not cause true allergy; the sulfite antioxidant added to vasoconstrictor solutions is the more relevant sensitivity concern.$$, 1),
    (qid, $$C$$, $$prolong bleeding at the injection site$$, false, $$Vasoconstriction reduces bleeding in the field — the opposite effect.$$, 2),
    (qid, $$D$$, $$make the solution more alkaline and dangerously speed onset$$, false, $$Vasoconstrictor-containing solutions are actually more acidic, and pH is not the reason to limit epinephrine in cardiac patients.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Epinephrine is a sympathomimetic: it raises heart rate, contractility, and blood pressure, which
increases myocardial oxygen demand. In a cardiovascularly compromised patient this added cardiac
stress is the concern, so the dose is held to a conservative "cardiac dose" (about 0.04 mg per
appointment) with careful aspiration.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

