    $$question$$,
    $$Local anesthetics produce their clinical effect primarily by:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — mechanism of action$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$destroying the myelin sheath surrounding the nerve fiber$$, false, $$Local anesthetics do not damage the myelin sheath; the effect is a reversible channel blockade, not structural nerve injury.$$, 0),
    (qid, $$B$$, $$blocking voltage-gated sodium channels in the nerve membrane, preventing depolarization$$, true, NULL, 1),
    (qid, $$C$$, $$competitively binding acetylcholine receptors at the neuromuscular junction$$, false, $$Acetylcholine receptor blockade describes neuromuscular blocking agents (e.g., used in general anesthesia), not local anesthetics.$$, 2),
    (qid, $$D$$, $$causing irreversible protein denaturation within the axon$$, false, $$The anesthetic effect is reversible and does not involve denaturing axonal proteins.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The uncharged base form of the local anesthetic diffuses across the nerve membrane, where it
re-ionizes; the charged cationic form then binds a receptor site inside the voltage-gated sodium
channel, blocking sodium influx. This prevents the membrane depolarization needed to reach
threshold, so the action potential cannot propagate and the nerve is reversibly blocked.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

