  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$mylohyoid nerve$$, true, NULL, 0),
    (qid, $$B$$, $$buccal nerve$$, false, $$The buccal (long buccal) nerve supplies buccal soft tissue in the molar region, not pulpal sensation to the teeth themselves.$$, 1),
    (qid, $$C$$, $$greater palatine nerve$$, false, $$The greater palatine nerve innervates the posterior hard palate, unrelated to mandibular molar sensation.$$, 2),
