  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$para-aminobenzoic acid (PABA), a well-documented allergen$$, true, NULL, 0),
    (qid, $$B$$, $$methemoglobin, which triggers an IgE-mediated response$$, false, $$Methemoglobinemia is a dose-related toxic effect of certain agents (e.g., prilocaine, benzocaine), not an immune-mediated allergic mechanism.$$, 1),
    (qid, $$C$$, $$epinephrine breakdown products that cross-react with the immune system$$, false, $$Epinephrine metabolism is unrelated to the ester-vs-amide allergy distinction.$$, 2),
    (qid, $$D$$, $$a byproduct identical to penicillin, provoking cross-reactivity in penicillin-allergic patients$$, false, $$Ester metabolites are not chemically related to penicillin; there is no expected cross-reactivity with penicillin allergy.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Esters (e.g., procaine, benzocaine) are hydrolyzed by plasma pseudocholinesterase into metabolites
that include PABA, a recognized allergen and sensitizer. This is why documented true allergy is
almost always tied to ester agents. Amides (e.g., lidocaine, articaine) are metabolized mainly in
the liver and do not produce PABA, so genuine amide allergy is rare — many reported "allergies" to
amides are actually reactions to bisulfite preservatives, vasoconstrictor effects, or vasovagal
episodes.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
