  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$ester class, at a lower concentration to reduce allergen exposure$$, false, $$Using any ester-class agent, even diluted, still exposes an allergic patient to the class of concern and is unnecessary when a safe amide alternative exists.$$, 0),
    (qid, $$B$$, $$amide class, such as lidocaine, since true cross-sensitivity between ester and amide classes is not expected$$, true, NULL, 1),
    (qid, $$C$$, $$ester class, but only after premedicating with an oral antihistamine$$, false, $$Premedicating with an antihistamine to "cover" a known allergen exposure is not an accepted substitute for simply avoiding the allergen.$$, 2),
    (qid, $$D$$, $$neither class; pretopical anesthesia should be skipped entirely for this patient$$, false, $$Skipping pretopical anesthesia denies the patient an established comfort measure that is unnecessary to withhold once a safe amide topical is available.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Ester and amide local anesthetics are metabolized differently and do not share the allergenic
mechanism responsible for most reported "anesthetic allergies" (which is more often the
para-aminobenzoic acid metabolite of esters, or sulfite preservatives in vasoconstrictor
solutions). A patient with a true ester allergy can safely use an amide topical, such as
lidocaine, before an amide injection.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-anes-0014$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pharmacology$$ and coalesce(subdomain, '') = $$Local Anesthesia$$),
    $$question$$,
    $$A patient with severe trismus from a recent TMJ flare-up cannot open the mouth wide enough for a
standard inferior alveolar nerve block landmark approach. Which injection technique is most
appropriate for anesthetizing the mandibular quadrant?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — Vazirani-Akinosi (closed-mouth) mandibular block$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Vazirani-Akinosi closed-mouth mandibular block$$, true, NULL, 0),
    (qid, $$B$$, $$Gow-Gates block, using the standard wide-open landmarks$$, false, $$The Gow-Gates technique also requires a wide-open mouth to locate the condylar neck landmark, so it is not usable in significant trismus.$$, 1),
    (qid, $$C$$, $$Standard inferior alveolar nerve block, injecting slightly higher than usual$$, false, $$A standard IANB depends on visualizing/palpating landmarks reached with a wide-open mouth; simply adjusting injection height does not solve the access problem.$$, 2),
    (qid, $$D$$, $$Mental nerve block alone to cover the full quadrant$$, false, $$The mental nerve block only anesthetizes the lip/chin and facial gingiva anterior to the mental foramen — it does not anesthetize the pulps of the mandibular teeth or lingual tissues.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The Vazirani-Akinosi technique is a closed-mouth mandibular block performed with the teeth in
occlusion (or as close to it as the patient can manage), using the mucogingival junction of the
maxillary arch and the height of the mandibular ramus as landmarks instead of a wide-open jaw. This
makes it the technique of choice for patients with limited mandibular opening (trismus, TMJ
disorders, or post-surgical restriction) who cannot achieve the mouth opening a standard IANB or
Gow-Gates approach requires.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-anes-0015$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pharmacology$$ and coalesce(subdomain, '') = $$Local Anesthesia$$),
    $$completion$$,
    $$For a patient with significant cardiovascular disease (e.g., recent myocardial infarction, poorly
controlled hypertension), current guidance on local anesthetic with epinephrine 1:100,000 is to:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — vasoconstrictor dose limits in cardiovascular disease$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$limit epinephrine to no more than 0.04 mg (about two cartridges), aspirate before each injection, and inject slowly$$, true, NULL, 0),
    (qid, $$B$$, $$avoid all vasoconstrictors and use plain mepivacaine or plain prilocaine only, regardless of the procedure$$, false, $$Eliminating vasoconstrictor entirely is not the default recommendation for stable cardiovascular disease; plain solutions have a shorter duration and higher total anesthetic uptake, and adequate pain control itself reduces endogenous catecholamine release from stress. Vasoconstrictor-free anesthesia is reserved for more severe, unstable, or specifically contraindicated cases.$$, 1),
    (qid, $$C$$, $$use a higher epinephrine concentration (1:50,000) to shorten total anesthetic exposure time$$, false, $$A higher epinephrine concentration increases cardiovascular stimulant exposure per volume injected — the opposite of what is indicated — and 1:50,000 is not recommended for these patients.$$, 2),
    (qid, $$D$$, $$there is no need to modify anesthetic technique in cardiovascular disease as long as the patient is asymptomatic that day$$, false, $$A history of significant cardiovascular disease (recent MI, unstable angina, poorly controlled hypertension/arrhythmia) requires dose modification and careful technique regardless of how the patient feels on a given day; medical consult/clearance is often warranted first.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Conservative, widely cited guidance (echoed by the ADA and AHA) caps epinephrine at roughly 0.04 mg
in patients with significant cardiovascular disease — about two cartridges of a 1:100,000
formulation — while still using slow injection and aspiration to minimize the chance of an
intravascular bolus. This allows the real benefits of a vasoconstrictor (deeper anesthesia, reduced
systemic uptake of the anesthetic, less need for supplemental injections) while limiting the
cardiovascular stimulant load.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-anes-0016$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pharmacology$$ and coalesce(subdomain, '') = $$Local Anesthesia$$),
    $$question$$,
    $$Prilocaine and, to a lesser extent, articaine carry a dose-dependent risk of which adverse effect,
caused by a metabolite that oxidizes the iron in hemoglobin and impairs its oxygen-carrying
capacity?$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — prilocaine/articaine and methemoglobinemia$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Methemoglobinemia$$, true, NULL, 0),
    (qid, $$B$$, $$Malignant hyperthermia$$, false, $$Malignant hyperthermia is triggered by volatile inhalation anesthetics and succinylcholine, not by amide local anesthetics such as prilocaine or articaine.$$, 1),
    (qid, $$C$$, $$Status epilepticus$$, false, $$Status epilepticus can theoretically follow severe local anesthetic CNS toxicity from an intravascular overdose, but that is a generic overdose effect, not the specific dose-dependent mechanism described (an oxidized-hemoglobin metabolite).$$, 2),
    (qid, $$D$$, $$Agranulocytosis$$, false, $$Agranulocytosis is a drug-induced blood dyscrasia associated with certain other medications, not a recognized effect of prilocaine or articaine metabolism.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Prilocaine is metabolized to o-toluidine, which oxidizes hemoglobin's ferrous iron (Fe2+) to the
ferric state (Fe3+), forming methemoglobin that cannot carry oxygen; articaine carries a smaller
version of this same risk. At high cumulative doses this can produce clinically significant
methemoglobinemia — presenting as cyanosis that does not improve with supplemental oxygen — so
total dose is limited, especially in patients who are anemic, have cardiopulmonary disease, are
very young, or are taking other methemoglobin-inducing drugs.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-anes-0017$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pharmacology$$ and coalesce(subdomain, '') = $$Local Anesthesia$$),
    $$completion$$,
    $$Adding sodium bicarbonate to buffer a local anesthetic solution just before injection is intended
to raise the solution's pH closer to the drug's pKa, which:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — buffering local anesthetic solutions$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$increases the proportion of drug in the uncharged (base) form, speeding diffusion across the nerve sheath and onset of action$$, true, NULL, 0),
    (qid, $$B$$, $$permanently deactivates the vasoconstrictor so it cannot cause local ischemia$$, false, $$Buffering does not deactivate epinephrine; it is done carefully and close to the time of injection because a higher pH can accelerate vasoconstrictor breakdown if solutions sit too long, not because the vasoconstrictor is intentionally disabled.$$, 1),
    (qid, $$C$$, $$converts the anesthetic from an amide to an ester, changing how it is metabolized$$, false, $$Buffering changes solution pH, not the drug's chemical class; an amide anesthetic remains an amide, metabolized in the liver.$$, 2),
    (qid, $$D$$, $$extends the anesthetic's duration of action well beyond its unbuffered formulation$$, false, $$Buffering primarily speeds onset; it does not reliably extend how long the anesthetic lasts, which is governed mainly by protein binding and vascularity at the injection site.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Local anesthetic solutions are manufacturer-formulated at an acidic pH (partly to keep the
vasoconstrictor stable), which favors the charged, ionized form of the drug. Buffering with sodium
bicarbonate raises the pH toward the drug's pKa, shifting more molecules into the lipid-soluble,
un-ionized base form that crosses the nerve sheath and axonal membrane more readily — producing a
faster onset and, often, a more comfortable injection.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-anes-0018$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Dental Hygiene Care Planning$$ and coalesce(subdomain, '') = $$Anxiety and pain control — Local anesthesia$$),
    $$question$$,
    $$A patient's medical history lists a tricyclic antidepressant (e.g., amitriptyline). When planning
local anesthesia with a vasoconstrictor for this patient, the most appropriate approach is to:$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — drug interactions with vasoconstrictors$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$administer a standard dental cartridge concentration of epinephrine (e.g., 1:100,000), aspirate carefully before injecting, and avoid epinephrine-impregnated gingival retraction cord$$, true, NULL, 0),
    (qid, $$B$$, $$withhold all local anesthesia until the patient's physician discontinues the tricyclic antidepressant$$, false, $$Discontinuing a patient's psychiatric medication is not within the hygienist's scope and is unnecessary; normal dental doses of vasoconstrictor are used safely with careful technique.$$, 1),
    (qid, $$C$$, $$use a local anesthetic with epinephrine at twice the usual concentration to ensure adequate hemostasis$$, false, $$Increasing the epinephrine concentration or dose worsens the interaction risk rather than managing it; standard concentrations and minimal effective doses are used instead.$$, 2),
    (qid, $$D$$, $$select a local anesthetic containing norepinephrine instead of epinephrine, since norepinephrine is unaffected by tricyclic antidepressants$$, false, $$Norepinephrine's pressor effect is potentiated by tricyclic antidepressants even more than epinephrine's, so substituting norepinephrine increases risk rather than avoiding it.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Tricyclic antidepressants block neuronal reuptake of norepinephrine, which can potentiate the
cardiovascular (pressor) effects of exogenously administered epinephrine and, especially,
norepinephrine. In the small doses delivered in standard dental cartridges, this interaction is
managed safely with careful technique — aspirating before injection, injecting slowly, and using
the lowest effective epinephrine concentration. The much higher epinephrine concentration in
gingival retraction cord makes that specific product the item to avoid in these patients.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-anes-0019$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pharmacology$$ and coalesce(subdomain, '') = $$Local Anesthesia$$),
    $$question$$,
    $$As a local anesthetic takes effect, a patient typically loses pain and temperature sensation
before losing touch, pressure, and motor function in the same area. This order of loss occurs
because:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — differential nerve fiber blockade$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$smaller-diameter, lightly or unmyelinated nerve fibers carrying pain and temperature are blocked before larger-diameter, more heavily myelinated fibers carrying touch, pressure, and motor function$$, true, NULL, 0),
    (qid, $$B$$, $$the anesthetic is deliberately injected closer to pain fibers than to touch and motor fibers$$, false, $$A single injection deposits anesthetic around the entire nerve trunk; the differential effect comes from fiber properties, not selective proximity to one fiber type over another.$$, 1),
    (qid, $$C$$, $$pain fibers regenerate more slowly than motor fibers, so they appear to be blocked first$$, false, $$Nerve fiber regeneration is unrelated to the reversible pharmacologic blockade produced by a local anesthetic, which does not involve any fiber damage or regeneration.$$, 2),
    (qid, $$D$$, $$touch and motor fibers require a higher total anesthetic volume, not a different blocking mechanism, so they simply take longer to fill the tissue$$, false, $$The differential blockade is explained by fiber diameter and myelination, not by anesthetic volume or a diffusion-only mechanism.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Local anesthetics block nerve fibers in a fairly predictable order related to fiber diameter and
degree of myelination: smaller, lightly myelinated A-delta and unmyelinated C fibers (pain,
temperature, and autonomic function) are blocked before larger, more heavily myelinated A-beta
and A-alpha fibers (touch, pressure, proprioception, and motor function). Recovery of sensation
occurs in the reverse order, with motor and pressure sensation typically returning before pain
sensation fully returns.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-anes-0020$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pharmacology$$ and coalesce(subdomain, '') = $$Local Anesthesia$$),
    $$question$$,
    $$A patient is scheduled for extensive quadrant scaling and root planing expected to take about
90 minutes, followed by an anticipated need for postoperative pain control into the evening. Which
local anesthetic is the best choice for the mandibular block to cover both the procedure and the
early postoperative period?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — duration of action by agent$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$bupivacaine with epinephrine 1:200,000$$, true, NULL, 0),
    (qid, $$B$$, $$mepivacaine 3% plain$$, false, $$Mepivacaine 3% plain has no vasoconstrictor, giving only a short pulpal duration (roughly 20–40 minutes) that would not reliably cover a 90-minute procedure, let alone provide postoperative coverage.$$, 1),
    (qid, $$C$$, $$lidocaine 2% with epinephrine 1:100,000$$, false, $$Lidocaine with epinephrine gives intermediate duration (about 60 minutes of pulpal anesthesia), which may not comfortably cover the full procedure and offers little postoperative benefit compared with a long-acting agent.$$, 2),
    (qid, $$D$$, $$prilocaine 4% plain$$, false, $$Prilocaine 4% plain is also short-to-intermediate acting and, without a vasoconstrictor, is the least likely of the choices to last through a long procedure or into the evening.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Bupivacaine is a long-acting amide anesthetic, with pulpal anesthesia lasting roughly 90–180
minutes and soft-tissue anesthesia extending several hours beyond that, making it well suited to
long procedures where extended postoperative analgesia is also desired.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-anes-0021$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Dental Hygiene Care Planning$$ and coalesce(subdomain, '') = $$Anxiety and pain control — Local anesthesia$$),
    $$question$$,
    $$A patient takes a nonselective beta-adrenergic blocker (e.g., propranolol) for hypertension. What
is the primary concern with using a local anesthetic containing epinephrine for this patient?$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Malamed, Handbook of Local Anesthesia — drug interactions with vasoconstrictors$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$unopposed alpha-receptor stimulation can cause a significant rise in blood pressure with reflex bradycardia$$, true, NULL, 0),
    (qid, $$B$$, $$the beta-blocker will completely inactivate the local anesthetic, so profound anesthesia cannot be achieved$$, false, $$Beta-blockers do not inactivate local anesthetic molecules or block their sodium-channel mechanism; anesthesia is still achieved.$$, 1),
    (qid, $$C$$, $$epinephrine will reverse the antihypertensive effect by directly blocking the beta receptor$$, false, $$Epinephrine acts on adrenergic receptors as an agonist; it does not competitively block beta receptors or reverse the antihypertensive drug's mechanism.$$, 2),
    (qid, $$D$$, $$the interaction only matters with articaine and does not apply to other amide anesthetics$$, false, $$The unopposed alpha-stimulation interaction applies to epinephrine itself, regardless of which local anesthetic (lidocaine, articaine, mepivacaine, etc.) it is combined with.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Nonselective beta-blockers block both beta-1 (cardiac) and beta-2 (vascular smooth muscle,
mediating vasodilation) receptors. When epinephrine is given to a patient on a nonselective
beta-blocker, its beta-2 vasodilatory effect is blocked while its alpha-mediated
vasoconstriction is unopposed, which can produce a significant rise in blood pressure and a
compensatory (reflex) bradycardia. Aspiration and use of the lowest effective epinephrine dose are
recommended; this differs from the tricyclic-antidepressant interaction, where the concern is
potentiation of epinephrine's pressor effect through a different mechanism.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

