    $$question$$,
    $$Clinical attachment level (CAL) is measured from the:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — clinical attachment level$$,
    now()
  )
  on conflict (slug) do update set
