  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$gingival margin to the base of the pocket$$, false, $$That describes probing depth, which is measured from the (movable) gingival margin and can mislead when there is recession or edema.$$, 0),
    (qid, $$B$$, $$cementoenamel junction to the base of the pocket$$, true, NULL, 1),
    (qid, $$C$$, $$mucogingival junction to the gingival margin$$, false, $$That describes the width of keratinized/attached tissue, not attachment level.$$, 2),
    (qid, $$D$$, $$gingival margin to the mucogingival junction$$, false, $$The gingival-margin-to-mucogingival-junction distance also relates to gingival width, not attachment.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$CAL is measured from a fixed anatomic landmark — the cementoenamel junction — to the base of the
sulcus or pocket. Because the reference point does not move, CAL reflects true attachment loss even
when the gingival margin has receded or is swollen.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
