  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$swollen, spongy gingiva that bleeds easily$$, true, NULL, 0),
    (qid, $$B$$, $$enamel hypoplasia of the developing teeth$$, false, $$Enamel hypoplasia arises from disturbances during enamel formation (e.g., febrile illness, fluorosis, vitamin A/D issues), not vitamin C deficiency.$$, 1),
    (qid, $$C$$, $$angular cheilitis at the corners of the mouth$$, false, $$Angular cheilitis is associated with B-complex (riboflavin) deficiency and Candida.$$, 2),
