  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$the total daily caloric intake from carbohydrates$$, false, $$Total caloric or sugar quantity matters less than how often the sugar is introduced across the day; a large single exposure produces one Stephan curve, not many.$$, 0),
    (qid, $$B$$, $$the frequency of fermentable carbohydrate exposures per day$$, true, NULL, 1),
    (qid, $$C$$, $$whether the carbohydrate is consumed with a meal or alone$$, false, $$Eating fermentable carbohydrate with a meal (versus alone as a snack) tends to blunt the pH drop via increased salivary flow and buffering, so this describes a protective timing factor, not the mechanism that worsens the curve.$$, 2),
    (qid, $$D$$, $$the fiber content of the food consumed$$, false, $$Fiber can increase salivary flow and mechanical clearance, which is protective, but it is not the factor that most directly worsens the pH drop itself.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Each fermentable-carbohydrate exposure triggers a Stephan curve — a rapid plaque pH drop below the
critical pH (~5.5) followed by a slow recovery. Frequent exposures keep plaque pH depressed for a
larger share of the day, shortening remineralization time and driving net demineralization, which
is why exposure frequency (not total sugar amount) is the strongest dietary predictor of caries
risk.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

