    $$A community program designer wants to increase sealant uptake by addressing parents' belief that
their child is unlikely to get cavities. Which health behavior model construct is this targeting?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Nathe, Dental Public Health and Research — health behavior models$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$perceived susceptibility$$, true, NULL, 0),
    (qid, $$B$$, $$perceived barriers$$, false, $$Perceived barriers refers to the practical obstacles to acting (cost, access, time), not to disbelief about personal risk.$$, 1),
    (qid, $$C$$, $$cues to action$$, false, $$Cues to action are external or internal prompts that trigger the decision to act (e.g., a reminder postcard), which is a different mechanism than correcting a risk misperception.$$, 2),
    (qid, $$D$$, $$self-efficacy$$, false, $$Self-efficacy is confidence in one's own ability to carry out the behavior successfully, not the belief about how likely the disease is to occur.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The Health Belief Model's perceived susceptibility construct describes a person's subjective sense
of their (or their child's) risk of developing a condition. Parents who underestimate their child's
caries risk have low perceived susceptibility, and targeting that belief directly (e.g., with risk
information) is the relevant lever for increasing preventive-service uptake such as sealants.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
