    (qid, $$A$$, $$conduct a needs assessment to identify the population's existing oral health status and resources$$, true, NULL, 0),
    (qid, $$B$$, $$select and purchase preventive materials such as fluoride varnish for distribution$$, false, $$Selecting materials without first assessing needs risks mismatching resources to the population's actual problems and priorities.$$, 1),
    (qid, $$C$$, $$write the program's final evaluation report$$, false, $$Evaluation is the final stage of the planning cycle (assess → plan → implement → evaluate), not the first.$$, 2),
