appropriate?$$,
    $$medium$$,
    $$approved$$,
    (select id from public.cases where slug = $$case-geri-0001$$),
    $$Wilkins — fluoride therapy for root caries in xerostomic patients$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$daily home use of a prescription-strength 5,000 ppm fluoride toothpaste$$, true, NULL, 0),
    (qid, $$B$$, $$an in-office fluoride varnish once, with no further follow-up needed$$, false, $$A single in-office varnish application gives short-term benefit but is not sufficient alone for a patient with ongoing high caries risk from chronic dry mouth; it should supplement, not replace, daily home fluoride.$$, 1),
    (qid, $$C$$, $$switching to an over-the-counter 1,100 ppm fluoride toothpaste used twice weekly$$, false, $$Standard 1,100 ppm toothpaste used less than daily is a step down in both concentration and frequency from what this high-risk patient needs.$$, 2),
    (qid, $$D$$, $$an acidulated phosphate fluoride rinse used once a month$$, false, $$Monthly professional rinse use is far too infrequent to counter continuous demineralization in a chronically hyposalivary mouth.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Patients with xerostomia and active root caries benefit most from a daily high-concentration
(5,000 ppm) prescription fluoride dentifrice, which provides continuous topical exposure to
remineralize root surfaces that are especially vulnerable once cementum and dentin are exposed by
recession. This is standard of care for xerostomia-related caries risk and is easy for a patient
with limited dexterity to work into an existing brushing routine.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
