  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$recommend a power toothbrush with an enlarged handle to compensate for her reduced hand dexterity from arthritis$$, true, NULL, 0),
    (qid, $$B$$, $$instruct her to switch to hard candy sweetened with xylitol as her main strategy for both dry mouth and caries control$$, false, $$Hard candy, even xylitol-sweetened, is not a substitute for a modified hygiene device; sugared hard candy specifically (as she currently uses) is actively contributing to her caries risk.$$, 1),
    (qid, $$C$$, $$tell her that once daily brushing quality declines, flossing should be discontinued entirely to simplify her routine$$, false, $$Reduced brushing quality is a reason to adapt the technique or device, not to eliminate an interdental cleaning aid altogether — that would raise, not lower, her risk.$$, 2),
    (qid, $$D$$, $$recommend she rely solely on her partial denture's clasps to hold plaque-retentive areas clean$$, false, $$Denture clasps do not clean tooth surfaces and are not a hygiene strategy; this ignores the actual problem.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Individualized education should adapt the mechanics of home care to the patient's actual
limitations. A power toothbrush with a built-up or enlarged handle requires less fine motor control
than a manual brush and can meaningfully improve plaque removal for a patient whose osteoarthritis
has reduced her hand dexterity — directly addressing the plaque accumulation noted in her exam.$$)
