    $$question$$,
    $$Before beginning scaling and root planing for this patient taking warfarin, the most appropriate
step is to:$$,
    $$hard$$,
    $$approved$$,
    (select id from public.cases where slug = $$case-med-0001$$),
    $$Wilkins — anticoagulant therapy; Malamed — medical considerations$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$obtain a recent INR and consult her physician as needed, without independently stopping the warfarin$$, true, NULL, 0),
    (qid, $$B$$, $$instruct her to stop the warfarin for three days beforehand$$, false, $$Discontinuing warfarin is a physician's decision and can precipitate a dangerous clot; it is not done routinely for periodontal therapy.$$, 1),
    (qid, $$C$$, $$proceed right away, since scaling is non-invasive and cannot cause meaningful bleeding$$, false, $$Scaling and root planing can produce appreciable bleeding, so "non-invasive" is inaccurate here.$$, 2),
    (qid, $$D$$, $$have her double the warfarin dose to prevent clots during treatment$$, false, $$Increasing the dose raises bleeding risk and is outside the hygienist's scope.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$For an anticoagulated patient, confirm a current INR (ideally within about 24-72 hours) and
coordinate with the physician. When the INR is within the therapeutic range, scaling and root
planing can usually proceed with local hemostatic measures. The dental hygienist never alters
anticoagulation independently — stopping warfarin risks a thromboembolic event such as a stroke.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

