  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$International Normalized Ratio (INR)$$, true, NULL, 0),
    (qid, $$B$$, $$fasting blood glucose$$, false, $$Fasting blood glucose reflects diabetic control, not anticoagulation.$$, 1),
    (qid, $$C$$, $$white blood cell count$$, false, $$White blood cell count reflects infection or immune status, not clotting.$$, 2),
    (qid, $$D$$, $$resting heart rate$$, false, $$Resting heart rate is relevant to her atrial fibrillation but is not a measure of coagulation or bleeding risk.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Warfarin inhibits vitamin K-dependent clotting factors, and its effect is monitored by the
prothrombin time expressed as the INR. A higher INR indicates greater anticoagulation and bleeding
risk; the therapeutic range for atrial fibrillation is generally about 2.0-3.0.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
