  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$bidirectional — poorly controlled diabetes worsens periodontal disease severity, and periodontal infection can worsen glycemic control$$, true, NULL, 0),
    (qid, $$B$$, $$unrelated — diabetes has no established effect on periodontal status$$, false, $$Diabetes is a well-established major risk factor for periodontal disease, so the two are not unrelated.$$, 1),
    (qid, $$C$$, $$protective — hyperglycemia reduces the inflammatory response and lowers periodontal disease risk$$, false, $$Hyperglycemia impairs immune and healing responses, increasing — not decreasing — susceptibility to periodontal breakdown.$$, 2),
    (qid, $$D$$, $$unidirectional — periodontal disease affects blood glucose, but diabetes has no effect on periodontal tissues$$, false, $$Research shows diabetes also affects periodontal tissues, not only the reverse, so the relationship runs both ways rather than one way.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Extensive evidence supports a bidirectional relationship: poorly controlled diabetes impairs
neutrophil function and collagen metabolism, worsening periodontal destruction, while periodontal
inflammation raises systemic inflammatory mediators that reduce insulin sensitivity and complicate
glycemic control.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
