declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-micr-0001$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Microbiology and Immunology$$ and coalesce(subdomain, '') = $$Microbiology$$),
    $$question$$,
    $$Which microorganism is most strongly associated with the initiation of dental caries?$$,
    $$easy$$,
    $$approved$$,
    NULL,
    $$Marsh & Lewis, Oral Microbiology — cariogenic bacteria$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Porphyromonas gingivalis$$, false, $$Porphyromonas gingivalis is a key periodontal ("red complex") pathogen, not a caries initiator.$$, 0),
    (qid, $$B$$, $$Streptococcus mutans$$, true, NULL, 1),
    (qid, $$C$$, $$Aggregatibacter actinomycetemcomitans$$, false, $$Aggregatibacter actinomycetemcomitans is associated with localized aggressive periodontitis.$$, 2),
    (qid, $$D$$, $$Lactobacillus acidophilus$$, false, $$Lactobacillus species are linked to the *progression* of established lesions rather than initiation.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Streptococcus mutans is the principal initiator of caries: it adheres to the acquired pellicle,
synthesizes extracellular polysaccharides that build biofilm, and is highly acidogenic and aciduric,
demineralizing enamel.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

