    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Treponema denticola$$, true, NULL, 0),
    (qid, $$B$$, $$Streptococcus mutans$$, false, $$Streptococcus mutans is a primary cariogenic organism, not a member of the periodontal red complex.$$, 1),
    (qid, $$C$$, $$Actinomyces viscosus$$, false, $$Actinomyces viscosus is an early biofilm colonizer associated with root-surface caries, not the red complex.$$, 2),
    (qid, $$D$$, $$Fusobacterium nucleatum$$, false, $$Fusobacterium nucleatum belongs to the orange complex; it bridges early and late colonizers but is not one of the three red-complex species.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Socransky's red complex — P. gingivalis, T. forsythia, and T. denticola — is the microbial cluster
