    (qid, $$A$$, $$hard palate$$, false, $$Hard palate SCC is uncommon; palatal masses are more often of salivary-gland origin.$$, 0),
    (qid, $$B$$, $$dorsum of the tongue$$, false, $$The dorsum of the tongue is an uncommon site for SCC.$$, 1),
    (qid, $$C$$, $$posterior-lateral border and ventral surface of the tongue$$, true, NULL, 2),
