    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pathology$$ and coalesce(subdomain, '') = $$Oral pathology$$),
    $$question$$,
    $$Leukoplakia is clinically defined as a white plaque that:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Neville, Damm, Allen & Chi, Oral and Maxillofacial Pathology — leukoplakia$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$cannot be scraped off and cannot be attributed to any other identifiable disease$$, true, NULL, 0),
    (qid, $$B$$, $$wipes away easily with gauze, revealing an erythematous base$$, false, $$A white lesion that wipes off to reveal a red base describes pseudomembranous candidiasis (thrush), not leukoplakia.$$, 1),
    (qid, $$C$$, $$is always histologically diagnostic of squamous cell carcinoma$$, false, $$Leukoplakia is a clinical term, not a histologic one; only biopsy can determine whether dysplasia or carcinoma is actually present.$$, 2),
    (qid, $$D$$, $$resolves spontaneously within 24–48 hours without treatment$$, false, $$Leukoplakia is a persistent lesion by definition; a white lesion that resolves quickly after removing an irritant (e.g., traumatic keratosis) is not classified as leukoplakia.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Leukoplakia is a clinical diagnosis of exclusion: a white patch or plaque that cannot be rubbed
off and cannot be characterized clinically or pathologically as any other definable lesion. Some
lesions show epithelial dysplasia and carry premalignant potential, so biopsy is indicated.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
