  values (
    $$q-path-0004$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pathology$$ and coalesce(subdomain, '') = $$General pathology$$),
    $$question$$,
    $$A patient develops hives, facial swelling, and difficulty breathing within minutes of receiving an
injection of amide local anesthetic containing a sulfite preservative. This reaction is mediated by
which hypersensitivity mechanism?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Kumar, Robbins Basic Pathology — hypersensitivity reactions$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Type I — IgE-mediated$$, true, NULL, 0),
    (qid, $$B$$, $$Type II — cytotoxic antibody-mediated$$, false, $$Type II reactions involve antibodies (IgG/IgM) directed against antigens on the patient's own cell surfaces (e.g., hemolytic reactions), not a rapid systemic allergic response to a drug.$$, 1),
    (qid, $$C$$, $$Type III — immune complex-mediated$$, false, $$Type III reactions involve antigen-antibody immune complexes depositing in tissue (e.g., serum sickness), which develops over days, not minutes.$$, 2),
    (qid, $$D$$, $$Type IV — delayed, T-cell-mediated$$, false, $$Type IV reactions are cell-mediated and delayed, typically appearing 24–72 hours after exposure (e.g., allergic contact dermatitis to latex), not within minutes.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Type I hypersensitivity is an immediate reaction in which allergen-specific IgE bound to mast cells
and basophils triggers degranulation and release of histamine and other mediators on re-exposure,
producing urticaria, angioedema, and bronchospasm/anaphylaxis within minutes — matching this
patient's rapid-onset presentation.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-pedo-0001$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Dental Hygiene Care Planning$$ and coalesce(subdomain, '') = $$Individualized patient education — instruction: dental caries$$),
    $$question$$,
    $$The caries pattern in this child — cavitation on the maxillary incisors with the mandibular
incisors spared — is most consistent with:$$,
    $$medium$$,
    $$approved$$,
    (select id from public.cases where slug = $$case-pedo-0001$$),
    $$Wilkins, Clinical Practice of the Dental Hygienist — early childhood caries$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$early childhood caries from frequent bottle and cup exposure$$, true, NULL, 0),
    (qid, $$B$$, $$an inherited enamel formation defect$$, false, $$Inherited enamel defects (e.g., amelogenesis imperfecta) affect the dentition symmetrically, not in this bottle-caries distribution.$$, 1),
    (qid, $$C$$, $$dental fluorosis from excess fluoride$$, false, $$Fluorosis is diffuse and this community lacks water fluoridation, making excess fluoride unlikely.$$, 2),
    (qid, $$D$$, $$trauma to the anterior teeth$$, false, $$Trauma would not produce this bilateral, surface-specific caries pattern.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$This is the classic early-childhood-caries (nursing/bottle caries) pattern: frequent, prolonged
exposure to fermentable carbohydrate (milk, juice) — especially at sleep, when salivary flow falls
— demineralizes the maxillary incisors first. During sucking the tongue covers and protects the
mandibular incisors, so they are relatively spared. Management centers on reducing exposure
frequency, weaning from the bedtime bottle, and fluoride.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

