  values (
    $$q-perio-0001$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Periodontal Disease Management$$ and coalesce(subdomain, '') = $$Etiology and pathogenesis of periodontal diseases$$),
    $$question$$,
    $$The primary etiologic factor in the initiation of gingivitis and periodontitis is:$$,
    $$easy$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — etiology$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$dental plaque biofilm$$, true, NULL, 0),
    (qid, $$B$$, $$supragingival calculus$$, false, $$Calculus is a plaque-retentive local contributing factor, but it is the living biofilm on its surface that is causative.$$, 1),
    (qid, $$C$$, $$occlusal trauma$$, false, $$Occlusal trauma can aggravate an existing lesion but does not by itself initiate periodontitis.$$, 2),
    (qid, $$D$$, $$inadequate keratinized tissue$$, false, $$Reduced keratinized tissue is a modifying local factor, not the primary cause.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Dental plaque biofilm is the primary etiologic factor. Its bacteria and their products provoke the
host inflammatory response that drives gingival inflammation and, in susceptible hosts, periodontal
attachment and bone loss.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

