  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$surgically eliminate periodontal pockets$$, false, $$Pocket elimination by resection is a surgical objective, not the aim of nonsurgical therapy.$$, 0),
    (qid, $$B$$, $$disrupt and remove subgingival biofilm and calculus so the tissues can heal$$, true, NULL, 1),
    (qid, $$C$$, $$regenerate lost alveolar bone$$, false, $$SRP does not regenerate bone; that requires regenerative surgical procedures.$$, 2),
    (qid, $$D$$, $$lighten the color of the root surfaces$$, false, $$Changing root color is not a therapeutic objective.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Scaling and root planing mechanically removes subgingival plaque biofilm and calculus and disrupts
the microbial community, producing a biologically acceptable root surface. Inflammation then
resolves, with reduced probing depths and gains in clinical attachment.$$)
