  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-perio-0005$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Periodontal Disease Management$$ and coalesce(subdomain, '') = $$Etiology and pathogenesis of periodontal diseases$$),
    $$question$$,
    $$Which factor in this patient's history most increases her risk for progressive periodontal
attachment loss?$$,
    $$medium$$,
    $$approved$$,
    (select id from public.cases where slug = $$case-perio-0001$$),
    $$Newman & Carranza, Clinical Periodontology — systemic risk factors$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$poorly controlled type 2 diabetes (HbA1c 7.8%)$$, true, NULL, 0),
    (qid, $$B$$, $$a 15 pack-year smoking history that ended 5 years ago$$, false, $$Smoking is a major periodontal risk factor, but risk declines substantially after cessation; a 5-year former smoker carries less current risk than her uncontrolled glycemic status.$$, 1),
    (qid, $$C$$, $$use of a manual toothbrush$$, false, $$Manual toothbrush use is not itself a periodontal risk factor when technique is adequate.$$, 2),
    (qid, $$D$$, $$daily metformin use$$, false, $$Metformin is a diabetes management medication; it is not a periodontal risk factor and, unlike some other drug classes, does not cause gingival overgrowth.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Poorly controlled diabetes impairs neutrophil function and collagen metabolism, amplifying the
host inflammatory response to plaque biofilm and increasing risk for periodontal attachment loss.
It is a well-established, bidirectional periodontal risk factor.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
