    $$question$$,
    $$The primary purpose of periodontal maintenance (supportive periodontal therapy) after active
treatment is to:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — supportive periodontal therapy$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$monitor for recurrence and periodically disrupt the biofilm to control disease$$, true, NULL, 0),
    (qid, $$B$$, $$permanently cure the patient's periodontal disease$$, false, $$Periodontitis is managed, not cured; the goal is stability, not a permanent cure.$$, 1),
    (qid, $$C$$, $$replace the need for daily self-performed plaque control$$, false, $$Maintenance supplements, and depends on, effective daily home care — it does not replace it.$$, 2),
    (qid, $$D$$, $$whiten the teeth at each recall visit$$, false, $$Whitening is unrelated to the goals of periodontal maintenance.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Biofilm re-forms continuously, and periodontal susceptibility persists after therapy. Maintenance
visits (often every 3 months initially) re-evaluate probing depths and bleeding, remove new
deposits, and reinforce home care to prevent recurrence and detect progression early.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

