    (qid, $$B$$, $$stainless-steel sickle scaler$$, false, $$A steel scaler gouges and scratches titanium.$$, 1),
    (qid, $$C$$, $$standard metal-tipped ultrasonic insert$$, false, $$A standard metal ultrasonic tip also scratches the surface; only plastic-sheathed or implant-safe tips are appropriate.$$, 2),
