    $$question$$,
    $$A patient returns one week after periodontal flap surgery for suture and periodontal dressing
removal. Which home-care instruction is most appropriate for this visit?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — post-surgical care$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Resume gentle brushing with a soft brush in the surgical area and begin chlorhexidine rinses as directed$$, true, NULL, 0),
    (qid, $$B$$, $$Begin normal flossing and interdental brushing immediately in the surgical site$$, false, $$Flossing and interdental brushes are too traumatic to newly healing tissue at one week and are reintroduced later, once healing progresses.$$, 1),
    (qid, $$C$$, $$Discontinue all oral hygiene in the surgical area until the 6-week reevaluation$$, false, $$Prolonged avoidance of hygiene allows biofilm to accumulate and can compromise healing.$$, 2),
    (qid, $$D$$, $$Use a firm-bristle brush with vigorous scrubbing to remove new plaque buildup$$, false, $$Vigorous, firm-bristle brushing risks trauma to the healing surgical site.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Once sutures and dressing are removed, gentle mechanical cleaning with a soft brush can resume in
the surgical area, supplemented by chemotherapeutic plaque control (chlorhexidine) while tissue is
still fragile and interdental aids are not yet tolerated.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
