    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Periodontal Disease Management$$ and coalesce(subdomain, '') = $$Reassessment and evaluation$$),
    $$negative$$,
    $$At the 4- to 6-week periodontal reevaluation following scaling and root planing, all of the
following are appropriate to assess EXCEPT:$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — periodontal reevaluation$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$probing depths and bleeding on probing$$, false, $$Reduced probing depths and resolution of bleeding on probing are the primary clinical indicators of treatment response at reevaluation.$$, 0),
    (qid, $$B$$, $$gingival tissue tone and color$$, false, $$Firmer, less erythematous tissue reflects resolving inflammation and is assessed at reevaluation.$$, 1),
    (qid, $$C$$, $$plaque and biofilm control$$, false, $$Reevaluating plaque control identifies whether the patient's home care is adequate to sustain the treatment result.$$, 2),
    (qid, $$D$$, $$radiographic evidence of alveolar bone height change$$, true, NULL, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Soft-tissue healing and reduced inflammation are evaluated at 4-6 weeks post-therapy because
connective tissue reattachment and reduced probing depths are measurable by then. Radiographic bone
remodeling occurs far more slowly and is not expected to show meaningful change on a 4- to 6-week
film, so it is not a useful reevaluation measure at this interval.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

