    $$question$$,
    $$A locally delivered antimicrobial agent placed subgingivally as an adjunct to scaling and root
planing is most appropriately indicated for:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — locally delivered antimicrobials$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$generalized gingivitis with no attachment loss$$, false, $$Gingivitis without attachment loss resolves with improved biofilm control and mechanical debridement; a subgingival antimicrobial is not indicated.$$, 0),
    (qid, $$B$$, $$an isolated periodontal pocket that has not responded adequately to mechanical therapy alone$$, true, NULL, 1),
    (qid, $$C$$, $$full-mouth disinfection in a patient with generalized severe periodontitis$$, false, $$Full-mouth generalized disease is managed with systemic/mechanical strategies; localized agents are for isolated refractory sites, not a full-mouth approach.$$, 2),
    (qid, $$D$$, $$routine maintenance visits with no active disease present$$, false, $$With no active disease present, there is no indication for placing an antimicrobial agent.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Locally delivered antimicrobials are indicated as a site-specific adjunct for isolated, persistent
pockets (commonly ≥5 mm with continued inflammation) that have not fully resolved after
conventional scaling and root planing, delivering a sustained, high local drug concentration
directly into the pocket.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
