    $$question$$,
    $$Which group of bacteria is most strongly associated with progressive chronic periodontitis and
increasing probing depth?$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — periodontal microbiology, red complex$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Streptococcus mutans and Lactobacillus species$$, false, $$S. mutans and Lactobacillus are the primary cariogenic organisms associated with dental caries, not periodontal destruction.$$, 0),
    (qid, $$B$$, $$the "red complex": Porphyromonas gingivalis, Tannerella forsythia, and Treponema denticola$$, true, NULL, 1),
    (qid, $$C$$, $$Actinomyces viscosus and Actinomyces naeslundii$$, false, $$Actinomyces species are early/supragingival plaque colonizers associated more with gingivitis and calculus formation than with periodontal disease progression.$$, 2),
    (qid, $$D$$, $$Streptococcus sanguinis and Streptococcus mitis$$, false, $$S. sanguinis and S. mitis are early, health-associated pioneer colonizers of the pellicle, not markers of periodontal pathogenesis.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The red complex organisms — P. gingivalis, T. forsythia, and T. denticola — are late colonizers of
subgingival biofilm that are strongly and consistently associated with deepening pockets, bleeding
on probing, and progressive attachment loss in chronic periodontitis.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

