    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Periodontal Disease Management$$ and coalesce(subdomain, '') = $$Prescribed therapy — Chemotherapeutic agents$$),
    $$completion$$,
    $$Subantimicrobial-dose doxycycline (SDD), prescribed as an adjunct to scaling and root planing,
works by:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — host modulation therapy$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$directly killing periodontal pathogens at the low dose prescribed$$, false, $$Antibacterial killing requires antimicrobial dosing; SDD is deliberately dosed below that threshold precisely to avoid an antibacterial effect (and the resistance risk that comes with it).$$, 0),
    (qid, $$B$$, $$inhibiting host-derived matrix metalloproteinases (MMPs) that break down connective tissue and bone$$, true, NULL, 1),
    (qid, $$C$$, $$selectively suppressing only gram-negative anaerobes$$, false, $$SDD's mechanism is host-directed (anti-collagenase), not a selective antibacterial action against any bacterial subgroup.$$, 2),
    (qid, $$D$$, $$forming a substantive antimicrobial film over the root surface$$, false, $$Substantive antimicrobial films describe agents like chlorhexidine, not a systemic host modulation drug.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$At the subantimicrobial dose (20 mg twice daily) used for host modulation, doxycycline does not
reach levels that kill bacteria. Instead it inhibits collagenase and other host-derived matrix
metalloproteinases, reducing the connective tissue and bone breakdown driven by the host's own
inflammatory response — an adjunct to, not a replacement for, mechanical debridement.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

