  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$peri-implant mucositis$$, true, NULL, 0),
    (qid, $$B$$, $$peri-implantitis$$, false, $$Peri-implantitis requires both soft-tissue inflammation and progressive radiographic bone loss beyond initial remodeling; bone level here is unchanged from baseline.$$, 1),
    (qid, $$C$$, $$implant failure from occlusal overload$$, false, $$Occlusal overload presents with progressive bone loss and possible implant mobility, not isolated soft-tissue bleeding with a stable radiograph.$$, 2),
