    (qid, $$A$$, $$refer for evaluation for possible periodontal surgery or additional targeted therapy at that site$$, true, NULL, 0),
    (qid, $$B$$, $$discharge the patient to a routine 6-month recall with no further action$$, false, $$A persistent deep, bleeding pocket is an active risk site; routine recall without addressing it risks continued disease progression.$$, 1),
    (qid, $$C$$, $$repeat full-mouth scaling and root planing on all sites, including the resolved ones$$, false, $$The other sites already responded to therapy; retreating them offers no benefit and doesn't address the one site that actually needs attention.$$, 2),
    (qid, $$D$$, $$conclude that the site is stable because probing depth alone does not indicate active disease$$, false, $$A deep pocket combined with bleeding on probing is a recognized indicator of continued inflammation and risk, not a benign finding to ignore.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$A residual probing depth of 5 mm or more with bleeding on probing after nonsurgical therapy
indicates an area that did not respond adequately and remains at risk for further attachment loss.
Isolated non-responding sites like this one are the classic indication for referral to consider
surgical access or other targeted therapy, even when the rest of the mouth has responded well.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

