  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$disrupting bacterial cell walls and inhibiting bacterial enzymes on contact, with limited oral substantivity compared with chlorhexidine$$, true, NULL, 0),
    (qid, $$B$$, $$binding electrostatically to oral surfaces for 8-12 hours of sustained antibacterial release, the same mechanism as chlorhexidine$$, false, $$Long substantivity (roughly 8-12 hours of sustained release from binding to oral surfaces) is the hallmark of chlorhexidine, not essential oil rinses — this is a key distinction tested between the two agents.$$, 1),
    (qid, $$C$$, $$selectively inhibiting only gram-negative anaerobic pathogens deep within the periodontal pocket$$, false, $$Essential oils act broadly against the supragingival plaque biofilm; they are not a targeted, pocket-penetrating therapy against specific anaerobic pathogens.$$, 2),
