    $$completion$$,
    $$A resorbable barrier membrane is placed over an intrabony defect during periodontal surgery
primarily to:$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Newman/Carranza-style periodontics text — guided tissue regeneration$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$exclude faster-growing gingival epithelium and connective tissue from the defect so that periodontal ligament and bone cells can selectively repopulate it, favoring true regeneration$$, true, NULL, 0),
    (qid, $$B$$, $$mechanically splint the mobile tooth to adjacent teeth during the healing phase$$, false, $$GTR membranes are not splints; tooth mobility is managed separately (e.g., with a periodontal splint) if indicated.$$, 1),
    (qid, $$C$$, $$deliver a sustained-release antibiotic directly into the defect over several weeks$$, false, $$A GTR membrane is a physical barrier, not a drug-delivery device; sustained antibiotic release describes a separate class of locally delivered antimicrobials.$$, 2),
    (qid, $$D$$, $$protect the surgical flap from bacterial contamination during the first 24 hours only, after which its role is complete$$, false, $$The membrane's exclusionary role is intended to persist through the critical early weeks of healing (well beyond 24 hours) while the periodontal ligament and bone cells repopulate the defect, not just the first day after surgery.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Guided tissue regeneration (GTR) is based on the principle of selective cell repopulation: because
epithelium and gingival connective tissue proliferate faster than periodontal ligament and bone
cells, an unprotected healing defect tends to fill with a long junctional epithelium rather than
new attachment. A barrier membrane physically excludes the faster epithelial/connective-tissue
cells from the defect space, giving the slower-growing periodontal ligament and bone cells time to
repopulate it — the intended outcome is true periodontal regeneration (new cementum, periodontal
ligament, and bone), not just repair.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
