    $$question$$,
    $$Which of the following is the strongest **modifiable** risk factor for developing
peri-implantitis?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — risk factors for peri-implant disease$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Cigarette smoking$$, true, NULL, 0),
    (qid, $$B$$, $$A history of treated periodontitis$$, false, $$A prior history of periodontitis is a well-established risk factor for peri-implantitis, but it is not modifiable — the patient cannot change their treatment history, so it doesn't fit the "modifiable" criterion the stem asks about.$$, 1),
    (qid, $$C$$, $$Male sex$$, false, $$Sex is not a consistently supported risk factor for peri-implant disease and is not modifiable in any case.$$, 2),
    (qid, $$D$$, $$Implant placement in the posterior mandible$$, false, $$Implant location (anterior vs. posterior, maxilla vs. mandible) is not itself a major established risk factor for peri-implantitis, and it isn't something the patient can modify.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Smoking is consistently identified as the leading modifiable risk factor for peri-implant disease —
it reduces gingival vascularity and impairs the local immune response, increasing both the
likelihood and severity of peri-implant bone loss. Because a patient can change this behavior,
smoking cessation counseling is a key part of implant maintenance and risk management.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

