    $$completion$$,
    $$At periodontal reevaluation, clinical attachment level (CAL) is preferred over probing depth alone
as the measure of treatment outcome because CAL...$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Darby & Walsh, Dental Hygiene: Theory & Practice — periodontal reevaluation outcome measures$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$is measured from a fixed reference point (the cementoenamel junction), so it distinguishes true attachment gain from an apparent pocket-depth reduction caused by gingival recession$$, true, NULL, 0),
    (qid, $$B$$, $$can be recorded without inserting a periodontal probe into the sulcus$$, false, $$CAL still requires a periodontal probe — the difference is the fixed reference point used (CEJ), not the instrument.$$, 1),
    (qid, $$C$$, $$is completely unaffected by examiner technique or probing force$$, false, $$CAL, like probing depth, is still subject to examiner variability in probing force and angulation; it is not immune to technique-related error.$$, 2),
    (qid, $$D$$, $$always decreases by the same amount as probing depth after therapy$$, false, $$Probing depth and CAL do not always change by the same amount — that is exactly the point: recession can shrink probing depth substantially while CAL changes very little or not at all.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Probing depth is measured from the free gingival margin, which can move — after therapy, tissue
shrinkage or recession can reduce probing depth even without any true gain in periodontal
attachment. CAL, measured from the fixed cementoenamel junction, isn't confounded by that gingival
margin movement, so a genuine reduction in CAL reflects real reattachment or new attachment rather
than just recession masking the pocket.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

