    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Shortened to about every 3 months, since smoking and residual deep pockets both raise the risk of disease recurrence$$, true, NULL, 0),
    (qid, $$B$$, $$Left at a standard 6-month interval, since recall frequency is not adjusted for individual risk factors$$, false, $$Recall frequency is explicitly risk-based in periodontal maintenance protocols — a one-size interval ignores the patient's elevated recurrence risk.$$, 1),
    (qid, $$C$$, $$Lengthened beyond 6 months, since active therapy has already been completed$$, false, $$Completing active therapy does not eliminate ongoing risk; unresolved risk factors (smoking, residual pockets) argue for closer, not longer, follow-up.$$, 2),
    (qid, $$D$$, $$Set only by insurance coverage limits, not by clinical risk factors$$, false, $$Clinical risk, not insurance policy, should drive the recommended recall interval, even though coverage may separately affect what the patient can afford.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Supportive periodontal therapy (maintenance) intervals are individualized by risk: patients with
modifiable risk factors like smoking, plus anatomic risk factors like residual deep pockets, are
more likely to have disease recurrence and progression, so they are typically recalled every 3–4
months rather than the standard 6 months used for low-risk, fully resolved patients.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
