    $$question$$,
    $$Compared with traditional quadrant scaling and root planing spread across several weeks, the
one-stage full-mouth disinfection protocol (all quadrants scaled within 24 hours, combined with
chlorhexidine rinse/gel/pocket irrigation) was developed primarily to:$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — one-stage full-mouth disinfection$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$reduce the chance that bacteria from untreated pockets recolonize already-treated sites during therapy$$, true, NULL, 0),
    (qid, $$B$$, $$eliminate the need for any follow-up periodontal maintenance visits$$, false, $$Full-mouth disinfection changes how initial therapy is delivered, not whether ongoing supportive periodontal maintenance is still needed afterward.$$, 1),
    (qid, $$C$$, $$allow the clinician to avoid using local anesthesia during instrumentation$$, false, $$The rationale for compressing scaling into 24 hours is microbiological (limiting recolonization), not a change in anesthesia technique; local anesthesia is still typically used for thorough instrumentation.$$, 2),
    (qid, $$D$$, $$replace host-modulation therapy as the primary treatment for aggressive periodontitis$$, false, $$Host-modulation therapy (e.g., subantimicrobial-dose doxycycline) targets the host inflammatory response and is an adjunct in select cases; full-mouth disinfection is a scheduling/antiseptic strategy for mechanical debridement, not a replacement for it.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$With quadrant-by-quadrant scaling spaced weeks apart, pathogenic bacteria in still-untreated
pockets (and on the tongue/tonsils/oral mucosa) can recolonize sites that were already
instrumented, a phenomenon sometimes called intraoral translocation. Treating the full mouth within
a short window, paired with an antiseptic to suppress bacteria at extra-pocket reservoirs, was
designed to reduce this cross-contamination and improve clinical outcomes.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-perio-0023$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Periodontal Disease Management$$ and coalesce(subdomain, '') = $$Etiology and pathogenesis of periodontal diseases$$),
    $$question$$,
    $$While bacterial biofilm initiates periodontal disease, most of the actual collagen and alveolar
bone destruction seen in periodontitis is caused directly by:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — host response and tissue destruction$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$the host's own immune-inflammatory response, including neutrophil enzymes, cytokines, and matrix metalloproteinases released in reaction to the biofilm$$, true, NULL, 0),
    (qid, $$B$$, $$mechanical trauma from normal mastication acting on inflamed tissue$$, false, $$Masticatory forces are not the mechanism of periodontal tissue breakdown; occlusal trauma is a separate, distinct process from inflammatory periodontal destruction.$$, 1),
    (qid, $$C$$, $$direct enzymatic digestion of bone by periodontal pathogens' exotoxins$$, false, $$Periodontal pathogens contribute virulence factors, but the bulk of bone and collagen loss is driven by the host's own inflammatory mediators, not direct bacterial enzymatic digestion of bone.$$, 2),
    (qid, $$D$$, $$osmotic pressure changes caused by increased crevicular fluid volume$$, false, $$Increased gingival crevicular fluid flow is a sign of inflammation, not a destructive mechanism itself; it does not directly cause collagen or bone loss.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Periodontal bacteria are the initiating factor, but most of the tissue destruction is
host-mediated: the immune-inflammatory response to bacterial antigens releases neutrophil
enzymes, pro-inflammatory cytokines (e.g., IL-1, TNF-alpha), and matrix metalloproteinases that
break down collagen and stimulate osteoclastic bone resorption. This host-response concept
explains why modifying the host response (e.g., host-modulation therapy) can slow disease
progression even when some bacterial challenge remains.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

