    $$question$$,
    $$A patient with generalized Stage III, Grade C periodontitis and a high bacterial load of
*Aggregatibacter actinomycetemcomitans* has completed scaling and root planing. The dentist wants
to add a short course of systemic antibiotics to improve clinical outcomes. Which combination is
most supported for this purpose?$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Newman & Carranza, Clinical Periodontology — systemic antibiotics as an adjunct to periodontal therapy$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$amoxicillin plus metronidazole$$, true, NULL, 0),
    (qid, $$B$$, $$topical chlorhexidine rinse alone, since systemic antibiotics provide no additional benefit once SRP is complete$$, false, $$Chlorhexidine is a valuable local chemotherapeutic agent, but in a high-risk Grade C case with a specific pathogen implicated, the evidence supports an adjunctive systemic antibiotic course rather than relying on a topical rinse alone.$$, 1),
    (qid, $$C$$, $$a single dose of oral penicillin V taken immediately before the SRP appointment$$, false, $$A single prophylactic dose before treatment is a strategy for preventing bacteremia-related complications in medically compromised patients, not a therapeutic antimicrobial regimen for aggressive periodontitis.$$, 2),
    (qid, $$D$$, $$long-term daily doxycycline at a full antimicrobial dose continued indefinitely$$, false, $$Long-term, full-dose antibiotic therapy is inappropriate; it promotes bacterial resistance and adverse effects. When doxycycline is used adjunctively, it is typically at a sub-antimicrobial dose for host modulation, not as a prolonged full-dose antibiotic course.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The combination of systemic amoxicillin and metronidazole (the "Van Winkelhoff" regimen), given
as a short adjunctive course alongside mechanical debridement, has the strongest evidence for
improving clinical attachment and reducing pocket depth in aggressive/Grade C periodontitis cases
associated with *A. actinomycetemcomitans*, which can persist in tissues and other intraoral
niches beyond the reach of instrumentation alone.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

