declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-phys-0001$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Physiology$$ and coalesce(subdomain, '') = $$$$),
    $$question$$,
    $$The rapid depolarization phase of a neuronal action potential is caused primarily by the influx of
which ion?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Guyton & Hall, Textbook of Medical Physiology — nerve conduction$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$potassium$$, false, $$Potassium efflux drives repolarization, returning the membrane toward its resting potential.$$, 0),
    (qid, $$B$$, $$calcium$$, false, $$Calcium influx is central to synaptic transmission and cardiac cells but is not the main driver of the nerve action potential upstroke.$$, 1),
    (qid, $$C$$, $$sodium$$, true, NULL, 2),
    (qid, $$D$$, $$chloride$$, false, $$Chloride movement is generally inhibitory (hyperpolarizing), not depolarizing.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$When threshold is reached, voltage-gated sodium channels open and Na+ rushes into the cell down its
electrochemical gradient, producing the rapid upstroke (depolarization). This is precisely the
mechanism local anesthetics interrupt by blocking those sodium channels.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

