    $$question$$,
    $$Which major salivary gland produces a purely serous secretion rich in the enzyme amylase?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Wilkins, Clinical Practice of the Dental Hygienist — saliva$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$submandibular gland$$, false, $$The submandibular gland is a mixed sero-mucous gland (predominantly serous) and is the main contributor to unstimulated saliva, but it is not purely serous.$$, 0),
    (qid, $$B$$, $$sublingual gland$$, false, $$The sublingual gland is predominantly mucous.$$, 1),
    (qid, $$C$$, $$parotid gland$$, true, NULL, 2),
    (qid, $$D$$, $$minor palatal glands$$, false, $$The minor palatal glands are mucous glands and produce little amylase.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The parotid gland secretes a purely serous fluid and is the major source of salivary α-amylase
