    $$question$$,
    $$Stimulation of which branch of the autonomic nervous system produces a profuse, watery salivary
secretion?$$,
    $$easy$$,
    $$approved$$,
    NULL,
    $$Standard physiology text — autonomic control of salivary secretion$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$parasympathetic$$, true, NULL, 0),
    (qid, $$B$$, $$sympathetic$$, false, $$Sympathetic stimulation constricts glandular vessels and yields a scant, thick, mucous-rich secretion, not a copious watery flow.$$, 1),
    (qid, $$C$$, $$somatic motor$$, false, $$The somatic motor system innervates skeletal muscle and has no direct role in glandular secretion.$$, 2),
