do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-plan-0001$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Dental Hygiene Care Planning$$ and coalesce(subdomain, '') = $$Recognition of emergency situations and provision of appropriate care$$),
    $$question$$,
    $$An otherwise healthy patient becomes pale, lightheaded, and briefly faints in the dental chair. The
most appropriate immediate management is to:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Malamed, Medical Emergencies in the Dental Office — syncope$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$sit the patient fully upright and offer a glass of water$$, false, $$Sitting the patient upright reduces cerebral perfusion and can prolong or deepen the faint.$$, 0),
    (qid, $$B$$, $$position the patient supine with the legs slightly elevated and ensure an open airway$$, true, NULL, 1),
    (qid, $$C$$, $$administer sublingual nitroglycerin$$, false, $$Nitroglycerin lowers blood pressure and is indicated for angina, which would worsen syncope.$$, 2),
    (qid, $$D$$, $$begin chest compressions$$, false, $$Chest compressions are for a pulseless patient; a fainting patient retains a pulse.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Vasovagal syncope is a transient loss of consciousness from reduced cerebral blood flow. Placing the
patient supine with legs slightly raised restores cerebral perfusion; the clinician then ensures an
open airway, monitors breathing and pulse, and may use an ammonia inhalant.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

