    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$book a long afternoon appointment after the patient has skipped lunch$$, false, $$Skipping a meal before a long appointment increases the risk of hypoglycemia.$$, 0),
    (qid, $$B$$, $$book a shorter morning appointment and confirm the patient has eaten and taken medication$$, true, NULL, 1),
    (qid, $$C$$, $$withhold all care until an endocrinology clearance is obtained$$, false, $$Well-controlled diabetes does not require medical clearance for routine hygiene care.$$, 2),
