    $$question$$,
    $$The most reliable way to confirm that a steam autoclave is actually achieving sterilization is:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$CDC Guidelines for Infection Control in Dental Settings; Wilkins — sterilization$$,
    now()
  )
  on conflict (slug) do update set
