    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$a biological (spore) test using resistant bacterial spores$$, true, NULL, 0),
    (qid, $$B$$, $$the color change on the autoclave indicator tape$$, false, $$Indicator tape is a chemical process indicator: it shows a package was exposed to heat, not that sterilizing conditions were achieved.$$, 1),
    (qid, $$C$$, $$confirming the programmed cycle time has elapsed$$, false, $$Elapsed time alone does not confirm that temperature and pressure were adequate throughout.$$, 2),
