  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Biological indicators contain highly heat-resistant spores (e.g., *Geobacillus stearothermophilus*).
If a cycle kills them, it has met the conditions lethal to essentially all microorganisms — the only
method that directly verifies sterilization. It is performed at least weekly.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
