    (qid, $$B$$, $$lay the patient supine and elevate the legs$$, false, $$A supine position with legs raised is management for syncope; it makes breathing harder in respiratory distress.$$, 1),
    (qid, $$C$$, $$give sublingual nitroglycerin$$, false, $$Sublingual nitroglycerin is for anginal chest pain, not bronchospasm.$$, 2),
