    $$question$$,
    $$Under current American Heart Association guidelines, antibiotic prophylaxis before an invasive
dental procedure is indicated for a patient with:$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$American Heart Association infective endocarditis prophylaxis guideline; Wilkins$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$a prosthetic (artificial) heart valve$$, true, NULL, 0),
    (qid, $$B$$, $$uncomplicated mitral valve prolapse without regurgitation$$, false, $$Mitral valve prolapse is no longer an indication for prophylaxis.$$, 1),
    (qid, $$C$$, $$a coronary artery stent placed two years ago$$, false, $$Coronary stents do not require antibiotic prophylaxis for dental care.$$, 2),
    (qid, $$D$$, $$well-controlled essential hypertension$$, false, $$Hypertension is unrelated to infective-endocarditis risk and needs no prophylaxis.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Since 2007 the AHA restricts prophylaxis to the cardiac conditions at highest risk for an adverse
outcome from infective endocarditis: prosthetic valves or prosthetic valve material, previous
infective endocarditis, certain congenital heart defects, and cardiac transplant recipients with
valvulopathy. A prosthetic heart valve qualifies.$$)
