    $$question$$,
    $$For a caries-active patient, the dietary counseling point most directly tied to lowering caries risk
is to reduce the:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Wilkins — diet and dental caries; Featherstone, caries balance$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$frequency of fermentable carbohydrate intake between meals$$, true, NULL, 0),
    (qid, $$B$$, $$total daily volume of water consumed$$, false, $$Water intake is not a caries driver (and adequate hydration supports salivary flow).$$, 1),
    (qid, $$C$$, $$intake of dietary calcium below the RDA$$, false, $$Lowering calcium would not help; it is not the modifiable caries factor here.$$, 2),
    (qid, $$D$$, $$number of times per day the teeth are brushed$$, false, $$Brushing more relates to biofilm removal, not diet; the question targets dietary counseling, and one would not advise brushing *less*.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Each exposure to fermentable carbohydrate drops plaque pH below the critical level for roughly 20+
minutes. Caries risk therefore tracks with how *often* teeth are challenged, so cutting the
frequency of between-meal sugars is the highest-yield dietary change.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
