    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$reversible with improved daily biofilm removal$$, true, NULL, 0),
    (qid, $$B$$, $$irreversible and will inevitably progress to periodontitis$$, false, $$Gingivitis does not inevitably progress; with adequate biofilm control it resolves without attachment loss.$$, 1),
    (qid, $$C$$, $$unrelated to daily oral hygiene practices$$, false, $$Gingivitis is directly caused by bacterial biofilm accumulation, so oral hygiene is central to both cause and resolution.$$, 2),
