  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Gingivitis is a reversible inflammatory response to bacterial biofilm at the gingival margin.
Emphasizing that consistent, effective daily plaque removal can restore gingival health motivates
the patient and sets realistic, achievable expectations.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
