    (qid, $$A$$, $$scaling and root planing of all affected quadrants$$, false, $$Scaling and root planing is the core periodontal disease-control intervention.$$, 0),
    (qid, $$B$$, $$oral hygiene instruction and reinforcement$$, false, $$Reinforced oral hygiene instruction is essential to arrest and prevent further disease.$$, 1),
    (qid, $$C$$, $$placement of the definitive fixed prosthesis$$, true, NULL, 2),
    (qid, $$D$$, $$caries excavation and temporary restorations to arrest active decay$$, false, $$Excavating active decay and placing temporary restorations stabilizes the dentition during disease control, before definitive restorative planning.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The disease-control phase aims to eliminate active infection and stabilize the dentition:
periodontal debridement, oral hygiene instruction, and interim restorative care to arrest decay.
Definitive fixed prosthodontics belongs to the later restorative/maintenance phase, after tissue
response to disease control has been reevaluated.$$)
