  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$explaining findings in language the patient can understand, avoiding technical jargon$$, false, $$Using plain language so the patient understands findings is a core element of effective case presentation.$$, 0),
    (qid, $$B$$, $$describing the risks, benefits, and alternatives to the proposed treatment$$, false, $$Disclosing risks, benefits, and alternatives is required for legally and ethically valid informed consent.$$, 1),
    (qid, $$C$$, $$pressuring the patient to accept the full plan in a single visit to avoid disease progression$$, true, NULL, 2),
    (qid, $$D$$, $$inviting the patient to ask questions and voice concerns before obtaining consent$$, false, $$Inviting questions and addressing concerns is appropriate and supports genuine informed consent.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Case presentation should support the patient's autonomous, informed decision-making. Pressuring a
patient to accept care undermines informed consent, which must be given voluntarily and free of
coercion, even when delaying treatment carries some clinical risk that should instead be explained
clearly.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
