    $$question$$,
    $$Under the Spaulding classification system, a mouth mirror that will contact oral mucosa but will
not penetrate soft tissue or bone is categorized as:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$CDC Guidelines for Infection Control in Dental Settings — Spaulding classification$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
