  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$critical, requiring disposal after a single use$$, false, $$Critical instruments are the ones that penetrate soft tissue or bone (e.g., scalers used subgingivally) and must be sterilized, not merely disposed of — and disposal isn't the defining requirement of the critical category anyway.$$, 0),
    (qid, $$B$$, $$semicritical, requiring at minimum high-level disinfection, with heat sterilization preferred$$, true, NULL, 1),
    (qid, $$C$$, $$noncritical, requiring only intermediate-level surface wiping$$, false, $$Noncritical items only contact intact skin (e.g., a blood pressure cuff); a mirror touching mucosa is semicritical, not noncritical.$$, 2),
    (qid, $$D$$, $$critical, requiring only a chemical indicator strip to confirm processing$$, false, $$A chemical indicator only shows exposure to a process, not that sterilization or high-level disinfection was actually achieved.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The Spaulding system sorts instruments by infection risk. Semicritical items contact mucous
membranes or nonintact skin but don't penetrate tissue, so they need at least high-level
disinfection; because most dental semicritical instruments can withstand heat, CDC guidance
prefers steam sterilization for them over disinfection alone.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
