    $$completion$$,
    $$When instructing a caries-active patient on fluoride toothpaste use, the hygienist should advise
the patient to spit out the excess after brushing but avoid rinsing with water immediately after,
because rinsing:$$,
    $$easy$$,
    $$approved$$,
    NULL,
    $$Wilkins, Clinical Practice of the Dental Hygienist — fluoride patient instructions$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
