    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$dilutes and clears the fluoride left on tooth surfaces and in saliva, reducing its remineralizing effect$$, true, NULL, 0),
    (qid, $$B$$, $$reactivates the abrasives in the toothpaste, increasing enamel wear$$, false, $$Rinsing does not reactivate abrasives; abrasive action happens during brushing, not after.$$, 1),
    (qid, $$C$$, $$neutralizes the fluoride ion, converting it into an inactive compound$$, false, $$Water rinsing dilutes and removes fluoride but does not chemically neutralize it.$$, 2),
    (qid, $$D$$, $$has no measurable effect on caries risk either way$$, false, $$Reducing post-brush fluoride contact time measurably lowers the topical benefit, which is why this instruction is given specifically to caries-active patients.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Topical fluoride works by remaining in contact with enamel and in saliva after brushing, where it
promotes remineralization and inhibits demineralization. Rinsing with water right after brushing
washes away much of that residual fluoride, so patients are coached to spit, not rinse, to get the
full topical benefit.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

