  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$inflammation confined to the gingiva that resolves completely with improved brushing$$, false, $$Describes gingivitis, the reversible precursor condition, not periodontitis.$$, 0),
    (qid, $$B$$, $$loss of periodontal attachment and supporting bone that will not spontaneously reverse with home care alone$$, true, NULL, 1),
    (qid, $$C$$, $$a bacterial infection limited to the enamel surface$$, false, $$Periodontal disease is a biofilm-driven infection of the supporting structures, not an enamel surface process.$$, 2),
    (qid, $$D$$, $$a temporary increase in probing depths that returns to baseline once plaque is removed$$, false, $$Attachment and bone loss in periodontitis persist after plaque control; probing depths may improve with therapy, but lost attachment does not return to pre-disease baseline on its own.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Gingivitis is reversible inflammation limited to the gingiva. Periodontitis, by definition, includes
loss of clinical attachment and alveolar bone — damage that improved oral hygiene alone cannot
regenerate, which is why the patient needs to understand active professional therapy and ongoing
maintenance are required to control, not just reverse, the disease.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
