    $$question$$,
    $$During the disease-control phase of therapy, a periodontal re-evaluation appointment is scheduled
primarily to:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Darby & Walsh, Dental Hygiene: Theory and Practice — re-evaluation and phased treatment planning$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$begin definitive restorative treatment immediately$$, false, $$Definitive restorative work follows disease control and re-evaluation, not the reverse.$$, 0),
    (qid, $$B$$, $$assess tissue response to initial therapy and determine whether further treatment, such as surgery, is indicated$$, true, NULL, 1),
    (qid, $$C$$, $$discharge the patient to a routine maintenance interval regardless of healing$$, false, $$Placing a patient on maintenance without evaluating healing skips the assessment the appointment exists to perform.$$, 2),
    (qid, $$D$$, $$obtain the patient's initial informed consent for the original treatment plan$$, false, $$Informed consent is obtained before treatment begins during case presentation, not at the post-therapy re-evaluation.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Re-evaluation, typically 4-6 weeks after nonsurgical therapy, measures how tissue responded —
reduced inflammation, probing depths, bleeding on probing — so the plan can be modified: some
sites may need only maintenance, while others with persistent pockets may require referral for
surgical therapy. It's a decision point, not an automatic step to the next phase.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
