  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$provide a detailed pamphlet covering the full biofilm etiology for the patient to study at home$$, false, $$Dense written material with technical terminology is a poor match for limited health literacy and is unlikely to be understood or used.$$, 0),
    (qid, $$B$$, $$use plain, non-technical language paired with hands-on demonstration and a teach-back check for understanding$$, true, NULL, 1),
    (qid, $$C$$, $$deliver all instruction in a single long, information-dense session to minimize chair time$$, false, $$A single long session risks information overload; instruction is better paced and reinforced over time.$$, 2),
    (qid, $$D$$, $$rely primarily on written post-visit instructions mailed after the appointment$$, false, $$Written instructions alone, without demonstration or teach-back, don't confirm comprehension and are easily misunderstood by a patient with limited health literacy.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Individualizing instruction means matching the method to the patient's ability to understand and
use the information. Plain language, hands-on demonstration (e.g., guiding the patient through
brushing technique in the mirror), and teach-back — having the patient show or explain it back —
confirm the instruction actually transferred, which matters most for patients with limited health
literacy.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
