    $$question$$,
    $$Which of the following is written as a properly structured dental hygiene diagnosis (unmet need,
related etiology, and supporting evidence)?$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Darby & Walsh, Dental Hygiene: Theory and Practice — Human Needs Conceptual Model, diagnostic statements$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$"Patient has moderate chronic periodontitis, stage II grade B."$$, false, $$States a dental/periodontal diagnosis (disease stage and grade), which is within the dentist's/periodontist's scope, not a human-needs-based dental hygiene diagnosis.$$, 0),
    (qid, $$B$$, $$"Deficit in the human need for skin/mucous membrane integrity related to inadequate plaque removal, as evidenced by generalized bleeding on probing and 4-5 mm pockets."$$, true, NULL, 1),
    (qid, $$C$$, $$"Scale and root plane teeth #2-15 using local anesthesia."$$, false, $$Describes a treatment intervention (a procedure to perform), not a diagnostic statement of patient need.$$, 2),
    (qid, $$D$$, $$"Recommend the patient purchase a power toothbrush."$$, false, $$Is a product recommendation, not a diagnosis — it doesn't identify an unmet need, etiology, or supporting evidence.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$A dental hygiene diagnosis names an unmet human need, links it to its likely etiology or
contributing factor ("related to"), and cites the clinical findings that support it ("as
evidenced by"). Option B does all three — it identifies the deficit, its cause, and the objective
findings — which is what distinguishes a diagnosis from a clinical finding or a treatment
instruction.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
