    $$completion$$,
    $$A well-sequenced case presentation discusses the clinical findings and diagnosis with the patient
before presenting the specific treatment recommendations, primarily so that the patient:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Darby & Walsh, Dental Hygiene: Theory and Practice — case presentation sequencing$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
