    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$can compare fee schedules across the recommended options before hearing about the problem$$, false, $$Fee schedules and payment logistics are administrative details, not the reason findings precede treatment in a case presentation.$$, 0),
    (qid, $$B$$, $$understands the problem being addressed before evaluating the proposed solution, supporting informed decision-making$$, true, NULL, 1),
    (qid, $$C$$, $$has time to schedule follow-up appointments before treatment is discussed$$, false, $$Appointment scheduling is a logistical step that follows the clinical conversation, not the purpose of the sequencing.$$, 2),
    (qid, $$D$$, $$can select specific product brands before treatment options are explained$$, false, $$Product selection is a minor implementation detail, not the rationale for discussing findings and diagnosis before treatment recommendations.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Presenting findings and diagnosis first gives the patient the clinical context needed to make sense
of why a treatment is being recommended. Reversing that order — leading with treatment before the
patient understands the problem — undermines informed consent, since a patient can't meaningfully
weigh options for a problem they haven't yet been shown.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
