    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$position the patient supine with legs elevated, activate EMS, and administer epinephrine IM in the anterolateral thigh$$, true, NULL, 0),
    (qid, $$B$$, $$have the patient rinse with cool water and observe for 15 minutes before deciding on further care$$, false, $$A "wait and observe" approach delays the one intervention (epinephrine) that reverses anaphylaxis and can allow rapid progression to airway obstruction or cardiovascular collapse.$$, 1),
    (qid, $$C$$, $$administer the patient's short-acting bronchodilator inhaler only, since the wheezing is the priority$$, false, $$A bronchodilator alone does not address the systemic mast-cell-mediated reaction or the risk of hypotension and airway swelling; epinephrine is required first.$$, 2),
    (qid, $$D$$, $$give an oral antihistamine tablet and reappoint the patient for a later date$$, false, $$Oral antihistamines act too slowly and address only histamine-mediated skin symptoms, not the acute cardiorespiratory threat of anaphylaxis; the patient cannot simply be rescheduled.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$This presentation — rapid-onset skin/mucosal swelling and hives with respiratory involvement
(wheezing) and a sign of impending shock (faintness) — is anaphylaxis, a life-threatening
emergency. First-line treatment is prompt intramuscular epinephrine (anterolateral thigh, mid-
outer thigh muscle), positioning the patient to support blood pressure (supine with legs elevated
if tolerated), activating emergency medical services, and administering oxygen while monitoring
airway, breathing, and circulation.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
