do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-plan-0023$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Dental Hygiene Care Planning$$ and coalesce(subdomain, '') = $$Anxiety and pain control — General (e.g., relaxation techniques)$$),
    $$completion$$,
    $$A patient with severe, long-standing dental phobia agrees to a graduated care plan: the first visit
is only a seat-and-tour of the operatory, the second adds a mirror exam with no instruments, and
later visits progressively introduce sound, then touch, then instrumentation, only once the patient
reports feeling calm at each step. This behavior-management approach is best identified as:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Darby & Walsh, Dental Hygiene: Theory and Practice — behavior management techniques$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$systematic desensitization$$, true, NULL, 0),
    (qid, $$B$$, $$tell-show-do$$, false, $$Tell-show-do is a single-visit technique (explain, demonstrate on a model, then perform); it does not describe a multi-visit hierarchy of exposure steps.$$, 1),
    (qid, $$C$$, $$voice control$$, false, $$Voice control uses tone, pace, and firmness during a procedure to gain attention and cooperation; it is not a graduated exposure plan.$$, 2),
    (qid, $$D$$, $$positive reinforcement$$, false, $$Positive reinforcement rewards desired behavior after it occurs and can be used within any technique, but it does not itself describe the staged exposure hierarchy in the vignette.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Systematic desensitization pairs relaxation with a graduated hierarchy of anxiety-provoking stimuli,
advancing to the next step only after the patient tolerates the current one calmly, across multiple
visits. That staged, multi-appointment structure — not a single pre-procedure demonstration — is
the defining feature described here.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
