    $$question$$,
    $$Immediately after an instrument causes a percutaneous sharps injury during patient care, the
dental hygienist's first and most appropriate action is to:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$CDC Bloodborne Pathogens/OSHA Standard — post-exposure management of percutaneous injuries$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$wash the wound with soap and water, then report the exposure per the office's post-exposure protocol for evaluation and possible follow-up$$, true, NULL, 0),
    (qid, $$B$$, $$apply bleach or another caustic disinfectant directly to the puncture site to kill any pathogens$$, false, $$Caustic agents like bleach are not recommended for wound care; they can damage tissue and do not replace the standard wash-and-report protocol.$$, 1),
    (qid, $$C$$, $$finish the current procedure on the patient first, then address the wound once the appointment ends$$, false, $$Exposure management should begin immediately, not be deferred until a procedure is finished; delay reduces the effectiveness of timely risk assessment and any indicated prophylaxis.$$, 2),
    (qid, $$D$$, $$apply a bandage and continue working without reporting, since minor sharps injuries do not require follow-up$$, false, $$All percutaneous sharps injuries require reporting under OSHA's Bloodborne Pathogens Standard, regardless of how minor the injury appears, so the exposure can be properly evaluated.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Current CDC/OSHA guidance for a percutaneous exposure is to immediately wash the wound with soap
and water (mucous membranes are flushed with water), then report the exposure right away so the
facility's post-exposure protocol can proceed — source-patient testing, risk assessment, and
timely post-exposure prophylaxis if indicated, since prophylaxis effectiveness is time-sensitive.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-plan-0025$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Dental Hygiene Care Planning$$ and coalesce(subdomain, '') = $$Individualized patient education — instruction: oral conditions$$),
    $$question$$,
    $$A patient reports sharp, short-lasting pain from cold beverages localized to a small area of
exposed root surface with no caries or defective restoration present. Along with an in-office
fluoride varnish application, which home-care instruction is most appropriate?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Wilkins, Clinical Practice of the Dental Hygienist — dentin hypersensitivity management$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$switch to a desensitizing dentifrice containing potassium nitrate or stannous fluoride and use it daily in place of a whitening toothpaste$$, true, NULL, 0),
    (qid, $$B$$, $$increase brushing frequency to six times daily with a medium-bristle brush to mechanically seal the exposed tubules$$, false, $$A medium or firm brush used more frequently increases the risk of further gingival recession and cervical abrasion, worsening tubule exposure rather than sealing it; a soft brush with gentle technique is indicated instead.$$, 1),
    (qid, $$C$$, $$discontinue fluoride toothpaste, since fluoride exposure is the most likely cause of the sensitivity$$, false, $$Fluoride toothpaste is not the cause of dentin hypersensitivity and is part of the recommended treatment (both varnish and fluoride dentifrice), not something to discontinue.$$, 2),
    (qid, $$D$$, $$rinse twice daily with a chlorhexidine gluconate mouthrinse until the sensitivity resolves$$, false, $$Chlorhexidine reduces bacterial plaque and gingival inflammation but has no established role in occluding dentinal tubules or blocking nerve conduction for hypersensitivity.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Dentin hypersensitivity from exposed root surfaces is managed with desensitizing agents:
potassium nitrate diffuses through open dentinal tubules to depolarize the intradental nerve and
reduce its ability to respond to stimuli, while stannous fluoride (and other agents such as
arginine/calcium carbonate) works primarily by occluding the tubules. Whitening dentifrices often
contain abrasives or peroxide that can worsen sensitivity, so switching away from one while adding
a desensitizing formula addresses both the mechanism and a likely aggravating factor.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
