    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Preventive Agents$$ and coalesce(subdomain, '') = $$Fluorides — Mechanisms of action$$),
    $$question$$,
    $$The primary mechanism by which topical fluoride reduces caries is:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Featherstone, caries balance; Wilkins — fluoride mechanisms$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$killing all cariogenic bacteria on contact$$, false, $$At typical topical concentrations fluoride inhibits bacterial metabolism but does not kill all cariogenic bacteria.$$, 0),
    (qid, $$B$$, $$promoting remineralization and forming acid-resistant fluorapatite$$, true, NULL, 1),
    (qid, $$C$$, $$mechanically sealing pits and fissures$$, false, $$Mechanically sealing pits and fissures describes sealants, not fluoride.$$, 2),
    (qid, $$D$$, $$increasing the resting salivary flow rate$$, false, $$Fluoride does not work by raising salivary flow.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Fluoride acts mainly topically: it drives remineralization of early enamel lesions and is
incorporated into the crystal lattice as fluorapatite, which is more resistant to acid dissolution.
At higher concentrations it also has a modest antibacterial and enzyme-inhibiting effect.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
