    (qid, $$A$$, $$tooth with frank cavitation extending into dentin$$, false, $$Frank cavitation into dentin requires a restoration, not a sealant.$$, 0),
    (qid, $$B$$, $$caries-free but deep, retentive occlusal pit or fissure at risk of caries$$, true, NULL, 1),
    (qid, $$C$$, $$smooth interproximal surface$$, false, $$Sealants are placed on pits and fissures, not smooth interproximal surfaces (managed with fluoride and interdental cleaning).$$, 2),
    (qid, $$D$$, $$tooth already restored with a full-coverage crown$$, false, $$A crowned tooth has no exposed occlusal fissure system to seal.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Sealants are indicated for sound or non-cavitated pit-and-fissure surfaces that are deep and
retentive and therefore at risk. The sealant physically occludes the fissure, denying bacteria and
fermentable carbohydrate access to the vulnerable surface.$$)
