  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$milk or another calcium-containing liquid$$, true, NULL, 0),
    (qid, $$B$$, $$a large glass of plain water only$$, false, $$Water may dilute but does not bind fluoride; calcium-containing liquids are preferred.$$, 1),
    (qid, $$C$$, $$a carbonated soft drink$$, false, $$A soft drink provides no calcium binding and its acidity is unhelpful.$$, 2),
    (qid, $$D$$, $$a citrus fruit juice$$, false, $$Fruit juice does not bind fluoride and adds acid.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Calcium binds fluoride in the gastrointestinal tract and slows its absorption, so milk (or another
calcium source) is given for fluoride ingestion while emergency care is arranged based on the dose
taken.$$)
