    $$question$$,
    $$Silver diamine fluoride (SDF) arrests active carious lesions primarily through which combined
mechanism?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Wilkins, Clinical Practice of the Dental Hygienist — silver diamine fluoride$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$the fluoride ion promotes remineralization while the silver ion is antibacterial$$, true, NULL, 0),
    (qid, $$B$$, $$the silver ion etches enamel while the fluoride ion whitens the lesion$$, false, $$SDF is not an etchant, and any lightening/whitening effect is not part of its mechanism — in fact treated lesions darken.$$, 1),
    (qid, $$C$$, $$both ions act only as a physical sealant barrier over the lesion$$, false, $$SDF penetrates and chemically acts on the lesion; it does not simply form a physical barrier the way a sealant resin does.$$, 2),
    (qid, $$D$$, $$the fluoride ion is antibacterial while the silver ion promotes remineralization$$, false, $$The roles are reversed: silver (not fluoride) provides the antibacterial effect, and fluoride (not silver) drives remineralization.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$SDF combines the antibacterial action of silver, which inhibits cariogenic bacteria such as
Streptococcus mutans, with fluoride's remineralizing effect on the demineralized tooth structure.
Together they arrest lesion progression non-invasively, at the cost of permanently staining the
treated carious tissue black.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

