    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Preventive Agents$$ and coalesce(subdomain, '') = $$Fluorides — Mechanisms of action$$),
    $$negative$$,
    $$All of the following are recognized mechanisms of fluoride's cariostatic action EXCEPT:$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Wilkins, Clinical Practice of the Dental Hygienist — mechanisms of fluoride action$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$promoting remineralization by favoring formation of fluorapatite in enamel$$, false, $$This is a true, well-established remineralization mechanism of fluoride.$$, 0),
    (qid, $$B$$, $$inhibiting bacterial enzymes (e.g., enolase) involved in glycolysis, reducing acid production$$, false, $$This is a true anti-metabolic mechanism of fluoride on cariogenic bacteria.$$, 1),
    (qid, $$C$$, $$acting as a bactericidal agent against cariogenic bacteria at sufficiently high, topical concentrations$$, false, $$This is a true direct antibacterial mechanism of fluoride at higher concentrations.$$, 2),
    (qid, $$D$$, $$inhibiting collagenase activity within the periodontal ligament to prevent attachment loss$$, true, NULL, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Fluoride's three established cariostatic mechanisms are: (1) inhibiting demineralization and
enhancing remineralization by forming the more acid-resistant fluorapatite/fluorhydroxyapatite,
(2) interfering with bacterial carbohydrate metabolism (e.g., inhibiting enolase), which reduces
acid production, and (3) exerting a direct antibacterial/bactericidal effect on cariogenic
bacteria at higher topical concentrations. Inhibiting periodontal ligament collagenase is not a
recognized fluoride mechanism; it is not part of how fluoride prevents dental caries.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

