  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$the smallest dose that produces any observable toxic symptoms$$, false, $$That describes a toxic (not lethal) threshold, sometimes called the "safely tolerated dose" boundary, a much smaller amount that causes GI upset, not death.$$, 0),
    (qid, $$B$$, $$the dose at which about half of an exposed population would be expected to die$$, false, $$A dose lethal to 50% of a population (an LD50) is a toxicology concept typically derived from animal studies, not the clinical CLD benchmark used for human fluoride emergencies.$$, 1),
    (qid, $$C$$, $$the lowest dose reported to have caused death in a human, without emergency treatment$$, true, NULL, 2),
    (qid, $$D$$, $$the maximum daily dose considered safe for long-term ingestion$$, false, $$The adequate/safe daily intake for ongoing exposure is an entirely different concept from a single acute lethal dose.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The "certainly lethal dose" (CLD) is the lowest reported dose that has caused death in a human
without treatment; for fluoride it is roughly 32-64 mg F per kg body weight, and it is the
benchmark used to decide whether emergency hospital referral is needed after an acute ingestion.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
