  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$cleaning the occlusal surface and isolating the tooth to maintain a dry field$$, false, $$Cleaning and maintaining a dry, isolated field is a required first step for good bonding.$$, 0),
    (qid, $$B$$, $$etching the enamel with phosphoric acid, then rinsing and drying to a frosty appearance$$, false, $$Acid-etching to a frosty, matte appearance creates the microporosities the resin tags flow into, essential for mechanical retention.$$, 1),
    (qid, $$C$$, $$applying a layer of fluoride varnish directly beneath the sealant to boost retention$$, true, NULL, 2),
    (qid, $$D$$, $$confirming the etched surface stays free of saliva contamination before applying the sealant$$, false, $$Saliva contamination of the etched surface is a leading cause of sealant failure, so confirming a dry field before applying the sealant is standard technique.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$This is a negative-format item — the key is the step that is NOT part of correct sealant technique.
Fluoride varnish is not applied beneath a sealant; a film of varnish (or any contaminant) between
the etched enamel and the resin would block the resin tags from penetrating the etched surface and
compromise retention.$$)
