end
$do$;

do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-prev-0009$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Preventive Agents$$ and coalesce(subdomain, '') = $$Other preventive agents (e.g., emerging materials)$$),
    $$question$$,
    $$Casein phosphopeptide-amorphous calcium phosphate (CPP-ACP) products promote remineralization of
early enamel lesions primarily by:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Wilkins, Clinical Practice of the Dental Hygienist — casein phosphopeptide-amorphous calcium phosphate (CPP-ACP)$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$binding calcium and phosphate ions and holding them in a bioavailable form at the tooth surface, buffering the reservoir for remineralization$$, true, NULL, 0),
    (qid, $$B$$, $$dissolving the outer enamel layer so new hydroxyapatite can form beneath it$$, false, $$CPP-ACP does not dissolve enamel; it supplies minerals for remineralization rather than removing tooth structure.$$, 1),
    (qid, $$C$$, $$forming an impermeable resin coating that blocks acid contact with enamel$$, false, $$Unlike a pit-and-fissure sealant, CPP-ACP is not a resin barrier — it is a topically applied paste/cream that releases ions, not a physical coating.$$, 2),
    (qid, $$D$$, $$lowering plaque pH directly to inhibit cariogenic bacteria$$, false, $$CPP-ACP's mechanism is mineral delivery, not direct antibacterial pH modification; that mechanism describes agents like xylitol or chlorhexidine, not CPP-ACP.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$CPP, a milk-derived casein phosphopeptide, stabilizes calcium and phosphate ions in an amorphous
(non-crystalline) complex that adheres to the tooth surface and biofilm, maintaining a supersaturated
local reservoir of these ions. This bioavailable calcium/phosphate diffuses into subsurface
demineralized enamel and promotes remineralization, and CPP-ACP is often paired with fluoride for an
added anticaries effect.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

