do $do$
declare qid uuid;
begin
  insert into public.questions (slug, taxonomy_id, format, stem, difficulty, status, case_id, reference, updated_at)
  values (
    $$q-prof-0005$$,
    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Professional Responsibility$$ and coalesce(subdomain, '') = $$Ethical principles$$),
    $$question$$,
    $$A dental hygienist notices that a colleague is consistently over-scheduling appointments so that
scaling and root planing is rushed and incomplete. Which ethical principle most directly obligates
the hygienist to address this?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$ADHA Code of Ethics for Dental Hygienists — core values$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$Nonmaleficence — the duty to avoid causing harm to patients$$, true, NULL, 0),
    (qid, $$B$$, $$Autonomy — the duty to respect a patient's right to self-determination$$, false, $$Autonomy concerns a patient's right to make informed choices about their own care, not the quality/thoroughness of the care being rendered.$$, 1),
    (qid, $$C$$, $$Justice — the duty to distribute resources and treatment fairly$$, false, $$Justice concerns fair distribution of care/resources across patients, not the completeness of one procedure.$$, 2),
    (qid, $$D$$, $$Confidentiality — the duty to protect private patient information$$, false, $$Confidentiality concerns protecting patient information, unrelated to rushed treatment.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Nonmaleficence ("do no harm") obligates clinicians to avoid practices that place patients at risk
of harm — here, rushed, incomplete periodontal therapy risks disease progression. This principle
supports raising the concern through appropriate channels (e.g., practice management, licensing
board if unresolved).$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

