    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$reciprocal supervision$$, true, NULL, 0),
    (qid, $$B$$, $$direct supervision$$, false, $$Direct supervision is a standard, widely used supervision category.$$, 1),
    (qid, $$C$$, $$general supervision$$, false, $$General supervision is a standard, widely used supervision category.$$, 2),
    (qid, $$D$$, $$indirect supervision$$, false, $$Indirect supervision is a standard, widely used supervision category.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Most state dental practice acts define hygienist scope of practice using categories such as
direct supervision (dentist present in the office and personally diagnoses/authorizes/checks the
procedure), indirect supervision (dentist present in the office but not necessarily observing),
and general supervision (dentist has authorized the treatment but need not be on-site). "Reciprocal
supervision" is not a recognized supervision-level term in dental practice acts.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
