  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$informed refusal, noting the risks disclosed and the patient's decision to decline$$, true, NULL, 0),
    (qid, $$B$$, $$informed consent, since the conversation about risks took place$$, false, $$Informed consent documents agreement to proceed with treatment, not a decision to decline it.$$, 1),
    (qid, $$C$$, $$incident report, since the patient did not follow the treatment plan$$, false, $$An incident report documents an adverse event or safety issue, not a patient's informed treatment decision.$$, 2),
