    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$rapidly dividing and undifferentiated$$, true, NULL, 0),
    (qid, $$B$$, $$mature and highly specialized$$, false, $$Mature, highly differentiated cells are comparatively radioresistant.$$, 1),
    (qid, $$C$$, $$in a permanent, non-dividing state$$, false, $$Permanent non-dividing cells (e.g., mature nerve and muscle) are among the most resistant.$$, 2),
    (qid, $$D$$, $$large and rich in cytoplasm$$, false, $$Cell size and cytoplasm volume are not the determinants of radiosensitivity.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Bergonié and Tribondeau observed that cells are most radiosensitive when they are rapidly dividing,
undifferentiated, and have a long mitotic future. This is why tissues such as bone marrow,
reproductive cells, and developing tissues are especially vulnerable to radiation.$$)
