    $$question$$,
    $$On a dental radiograph, which normal tooth structure appears the most radiopaque?$$,
    $$easy$$,
    $$approved$$,
    NULL,
    $$Iannucci, Dental Radiography: Principles and Techniques — radiographic anatomy$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
