  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$enamel$$, true, NULL, 0),
    (qid, $$B$$, $$dental pulp$$, false, $$The pulp is soft tissue and appears radiolucent (dark).$$, 1),
    (qid, $$C$$, $$the periodontal ligament space$$, false, $$The periodontal ligament space is a thin radiolucent line around the root.$$, 2),
    (qid, $$D$$, $$dentin$$, false, $$Dentin is mineralized but less so than enamel, so it appears less radiopaque.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Radiopacity reflects how much a structure attenuates the X-ray beam, which tracks with density and
mineral content. Enamel is the most highly mineralized tissue in the body, so it absorbs the most
radiation and appears the whitest (most radiopaque) on a radiograph.$$)
