    $$Compared with a conventional two-dimensional panoramic radiograph, cone-beam computed tomography
(CBCT) primarily offers the clinician:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$White & Pharoah, Oral Radiology: Principles and Interpretation — cone-beam CT$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
