    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$a three-dimensional volumetric image with no radiation exposure at all$$, false, $$CBCT still uses ionizing radiation; "no exposure at all" is never true of an X-ray-based technique.$$, 0),
    (qid, $$B$$, $$a three-dimensional volumetric image, generally at a higher patient dose than a panoramic$$, true, NULL, 1),
    (qid, $$C$$, $$a two-dimensional image with improved contrast but the same field of view$$, false, $$CBCT's advantage is the 3-D volume, not a same-field-of-view 2-D image.$$, 2),
    (qid, $$D$$, $$real-time fluoroscopic imaging of the temporomandibular joint$$, false, $$CBCT captures a static volumetric dataset, not continuous real-time fluoroscopy.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$CBCT reconstructs a three-dimensional volume from a single rotation of the source and a
flat-panel detector, letting the clinician view structures (impacted teeth, implant sites, the
TMJ) in any plane. That extra diagnostic information comes at an effective dose that is higher
than a panoramic image, though still well below a medical fan-beam CT, so its use should be
limited to cases where a 2-D image is insufficient.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

