    $$negative$$,
    $$All of the following factors primarily affect radiographic contrast EXCEPT:$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Iannucci, Dental Radiography: Principles and Techniques — image quality factors$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$kilovoltage (kVp)$$, false, $$Higher kVp increases beam penetration and produces a longer gray scale (lower contrast); it is a primary contrast factor.$$, 0),
    (qid, $$B$$, $$beam filtration$$, false, $$Filtration removes lower-energy photons, hardening the beam and altering contrast.$$, 1),
    (qid, $$C$$, $$exposure time$$, true, NULL, 2),
    (qid, $$D$$, $$subject density/thickness$$, false, $$Denser or thicker tissue absorbs more of the beam, changing the contrast between structures.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Contrast is the difference in density between adjacent areas of a radiograph and is governed
mainly by beam quality (kVp) and filtration, which set how much the beam's energy spectrum
penetrates versus scatters, along with the density/thickness of the tissue being imaged.
Exposure time instead controls the quantity of photons reaching the receptor, which primarily
changes overall image density (how dark/light the whole image is), not the contrast scale.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

