    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$reduce the radiation dose received by the operator$$, false, $$The dosimeter is a passive recording device; it does not attenuate or reduce the dose the operator actually receives.$$, 0),
    (qid, $$B$$, $$measure and record the cumulative occupational radiation exposure of the wearer$$, true, NULL, 1),
    (qid, $$C$$, $$shield the operator's thyroid from scatter radiation$$, false, $$A thyroid collar, not a dosimeter, shields the thyroid; the dosimeter is typically worn at collar level or on clothing to sample exposure, not to protect an organ.$$, 2),
    (qid, $$D$$, $$filter out low-energy photons before they reach the patient$$, false, $$Filtration to remove low-energy photons is a function of the X-ray tube's aluminum filter, not the personnel dosimeter.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$A personnel dosimeter does not protect the wearer; it is a monitoring device that measures and
records the cumulative radiation dose the operator receives over a defined period, allowing
comparison against occupational exposure limits and early detection of unsafe practices or
equipment malfunction.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
