    $$question$$,
    $$In a data set of resting heart rates that contains one extreme outlier, which measure of central
tendency is most resistant to that outlier?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Standard biostatistics text — measures of central tendency$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$mean$$, false, $$The mean is pulled toward extreme values and is therefore sensitive to outliers.$$, 0),
    (qid, $$B$$, $$median$$, true, NULL, 1),
    (qid, $$C$$, $$range$$, false, $$The range is a measure of spread, not central tendency, and is defined by the extremes.$$, 2),
    (qid, $$D$$, $$standard deviation$$, false, $$The standard deviation is a measure of spread and is inflated by values far from the mean.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The median is the middle value by rank, so a single extreme value barely shifts it. This makes the
median a robust (resistant) measure of central tendency when the data are skewed or contain outliers.$$)
