    (qid, $$A$$, $$case report$$, false, $$A case report is anecdotal and sits near the bottom of the evidence hierarchy.$$, 0),
    (qid, $$B$$, $$randomized controlled trial$$, true, NULL, 1),
    (qid, $$C$$, $$cross-sectional survey$$, false, $$A cross-sectional survey shows association at one point in time, not causation or efficacy.$$, 2),
