    (qid, $$A$$, $$correctly identifying people who truly have the disease, with few false negatives$$, true, NULL, 0),
    (qid, $$B$$, $$correctly identifying people who are truly disease-free$$, false, $$Correctly identifying disease-free people describes specificity, not sensitivity.$$, 1),
    (qid, $$C$$, $$confirming a diagnosis once disease is already strongly suspected$$, false, $$Confirming disease when suspected relates to specificity and positive predictive value.$$, 2),
