    $$question$$,
    $$A study reports p = 0.03 for the difference in mean probing depth reduction between two
scaling techniques, using an alpha of 0.05 set in advance. What does this p-value indicate?$$,
    $$hard$$,
    $$approved$$,
    NULL,
    $$Standard biostatistics text — hypothesis testing and the p-value$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$There is a 3% probability that the null hypothesis is true.$$, false, $$The p-value does not give the probability that the null hypothesis is true; that misinterpretation reverses what conditional probability the p-value describes.$$, 0),
    (qid, $$B$$, $$There is a 97% probability that the observed difference is clinically important.$$, false, $$Statistical significance (p < alpha) is distinct from clinical importance; a small, clinically trivial difference can still be statistically significant with a large enough sample.$$, 1),
    (qid, $$C$$, $$If the null hypothesis were true, a difference this large or larger would occur about 3% of the time by chance alone$$, true, NULL, 2),
    (qid, $$D$$, $$The alternative hypothesis has been proven correct.$$, false, $$Hypothesis testing never "proves" the alternative hypothesis; a low p-value only provides evidence against the null hypothesis within the stated significance level.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$The p-value is the probability of observing a result as extreme as, or more extreme than, the one
obtained, assuming the null hypothesis is true. A p-value of 0.03 falling below the pre-set alpha
of 0.05 leads the researcher to reject the null hypothesis, but the p-value itself is a statement
about the data given the null, not a probability statement about the null (or alternative)
hypothesis, and it says nothing about clinical significance.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

