    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$confounding variable$$, true, NULL, 0),
    (qid, $$B$$, $$dependent variable$$, false, $$The dependent variable is the outcome being measured (caries rate), not an extraneous factor distorting the relationship.$$, 1),
    (qid, $$C$$, $$null hypothesis$$, false, $$The null hypothesis is a statistical statement of no effect/association; it does not describe an uncontrolled third variable.$$, 2),
    (qid, $$D$$, $$placebo effect$$, false, $$A placebo effect is a psychological/physiological response to receiving a treatment (even an inactive one), unrelated to an uncontrolled variable like visit frequency.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$A confounding variable is a factor, other than the exposure being studied, that is associated with
both the exposure (gum chewing) and the outcome (caries) and can distort the apparent relationship
between them. Here, dental-visit frequency independently affects caries risk and is unevenly
distributed between groups, so it confounds the gum-chewing/caries association unless controlled for
(e.g., through randomization, matching, or statistical adjustment).$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

