    $$question$$,
    $$When applying research findings to an individual patient's care, evidence-based decision making
requires the clinician to integrate the best available scientific evidence with which other two
components?$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Forrest, Evidence-Based Decision Making — the EBDM triad$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
