  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$the clinician's professional expertise and the patient's needs, values, and preferences$$, true, NULL, 0),
    (qid, $$B$$, $$the manufacturer's marketing claims and the clinic's supply budget$$, false, $$Marketing claims and budget are not part of the evidence-based triad and are not appropriate substitutes for clinical evidence or patient-centered judgment.$$, 1),
    (qid, $$C$$, $$the most recently published study only and office scheduling constraints$$, false, $$A single recent study, without appraisal or context, and scheduling logistics do not represent the triad's clinician-expertise or patient-preference components.$$, 2),
    (qid, $$D$$, $$national practice averages and insurance reimbursement policy$$, false, $$Population-level averages and reimbursement policy may inform decisions but are not the defined components of evidence-based decision making.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Evidence-based decision making is defined as a three-part integration: the best available
