    (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Dental Hygiene Care Planning$$ and coalesce(subdomain, '') = $$Anxiety and pain control — General (e.g., relaxation techniques)$$),
    $$question$$,
    $$Which non-pharmacologic approach is most appropriate for reducing this nonverbal patient's anxiety
before and during instrumentation?$$,
    $$medium$$,
    $$approved$$,
    (select id from public.cases where slug = $$case-spec-0001$$),
    $$Wilkins, Clinical Practice of the Dental Hygienist — behavior guidance for patients with developmental disabilities$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$tell-show-do paired with a consistent, predictable visit routine and advance warning before each new sensation$$, true, NULL, 0),
    (qid, $$B$$, $$proceed directly with instrumentation without preview, since explanations will not be understood$$, false, $$Skipping any preview removes predictability and is more likely to trigger a defensive or sensory-overload reaction, not less.$$, 1),
    (qid, $$C$$, $$physically hold the patient's arms still without consent to shorten the appointment$$, false, $$Non-consensual physical restraint is inappropriate outside a documented, consented protective stabilization protocol and can cause physical or psychological harm; it is not a routine anxiety management technique.$$, 2),
    (qid, $$D$$, $$reschedule indefinitely until the patient can verbally agree to treatment$$, false, $$Verbal agreement is not the only valid form of assent — nonverbal patients can still receive care using adapted communication and behavior guidance; indefinite deferral denies needed preventive care.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Tell-show-do — demonstrating an instrument, letting the patient see and, when tolerated, touch or
hear it before it is used — combined with a predictable sequence of steps reduces uncertainty,
which is a major anxiety trigger for many patients with autism spectrum disorder. Consistency
across visits (same order of steps, advance warning before new stimuli) builds trust over time and
increases cooperation without medication or restraint.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

do $do$
