    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$switch to a soft-bristled or vibrating power toothbrush and an unflavored or mild-flavor fluoride toothpaste, keeping the same brushing routine and order each time$$, true, NULL, 0),
    (qid, $$B$$, $$substitute a non-fluoride toothpaste so taste sensitivity is no longer a concern$$, false, $$Fluoride remains the standard caries-preventive agent for this patient; taste sensitivity should be managed by choosing a mild or unflavored fluoride product, not by removing fluoride.$$, 1),
    (qid, $$C$$, $$reduce brushing to once every few days until the patient tolerates it better on his own$$, false, $$Reducing brushing frequency allows plaque and gingival inflammation to worsen and does not address the underlying sensory aversion.$$, 2),
    (qid, $$D$$, $$have the patient brush independently without caregiver assistance so he controls the sensory input$$, false, $$Given his level of support needs and difficulty completing brushing even with assistance, removing caregiver assistance is likely to result in incomplete plaque removal rather than improved tolerance.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Modifying the sensory inputs the patient is reacting to — bristle texture/vibration and taste —
while keeping the caregiver-assisted routine and sequence consistent addresses the specific
aversions without removing needed daily plaque control or fluoride exposure. A predictable order
of steps also reduces anxiety, reinforcing the desensitization approach used chairside.$$)
