    $$question$$,
    $$Selective (need-based) polishing is recommended primarily because routine coronal polishing:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Wilkins, Clinical Practice of the Dental Hygienist — selective polishing$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$takes too much appointment time to justify$$, false, $$Time is not the main rationale; the concern is unnecessary abrasion of tooth structure and restorations.$$, 0),
    (qid, $$B$$, $$can abrade the fluoride-rich outer enamel and exposed cementum without a therapeutic benefit$$, true, NULL, 1),
    (qid, $$C$$, $$always causes gingival bleeding$$, false, $$Polishing does not always cause bleeding.$$, 2),
    (qid, $$D$$, $$blocks the uptake of fluoride applied afterward$$, false, $$Polishing does not prevent later fluoride uptake — that is a myth; the real concern is loss of surface enamel.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Fluoride concentration is highest in the outermost enamel, and abrasive prophylaxis paste can remove
a thin layer of that surface as well as scratch exposed cementum, dentin, and esthetic restorations.
Because polishing is cosmetic (stain removal) rather than therapeutic, it should be done selectively,
only where extrinsic stain is present.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

