    $$question$$,
    $$Alginate (irreversible hydrocolloid) impression material sets by:$$,
    $$medium$$,
    $$approved$$,
    NULL,
    $$Standard dental materials text — irreversible hydrocolloid$$,
    now()
  )
  on conflict (slug) do update set
    taxonomy_id = excluded.taxonomy_id,
    format = excluded.format,
    stem = excluded.stem,
    difficulty = excluded.difficulty,
    status = excluded.status,
    case_id = excluded.case_id,
    reference = excluded.reference,
    updated_at = excluded.updated_at
  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$cooling and physical gelation$$, false, $$Cooling and physical gelation describes reversible (agar) hydrocolloid, which can be re-melted.$$, 0),
    (qid, $$B$$, $$an irreversible chemical cross-linking reaction$$, true, NULL, 1),
    (qid, $$C$$, $$evaporation of water from the mix$$, false, $$Alginate does not set by evaporation; premature water loss (syneresis) actually distorts it.$$, 2),
    (qid, $$D$$, $$light-curing under a curing lamp$$, false, $$Alginate is not a light-cured material.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Alginate is an irreversible hydrocolloid: it sets through a chemical reaction (calcium ions
replacing sodium and cross-linking the alginate), which cannot be reversed by reheating. The set
impression should be poured promptly to avoid dimensional change.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
