  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$is on a sodium-restricted diet$$, true, NULL, 0),
    (qid, $$B$$, $$has moderate extrinsic tobacco stain$$, false, $$Extrinsic stain is an indication for air polishing, not a contraindication.$$, 1),
    (qid, $$C$$, $$has a full gold crown on a molar$$, false, $$Gold restorations tolerate air polishing; the concern here is the sodium load, not the crown.$$, 2),
    (qid, $$D$$, $$drinks coffee and tea daily$$, false, $$Coffee and tea produce extrinsic stain — again an indication for stain removal.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Sodium bicarbonate air-polishing powder delivers appreciable sodium, so it is contraindicated for
patients on sodium-restricted diets (and used with caution in respiratory disease or uncontrolled
hypertension). A low-abrasive alternative such as glycine powder can be substituted.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
