  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$has smaller, rounder particles that are less abrasive to root dentin and titanium surfaces$$, true, NULL, 0),
    (qid, $$B$$, $$contains an antimicrobial agent that eliminates the need for subsequent instrumentation$$, false, $$Glycine powder is not antimicrobial; it is a mechanical biofilm-removal adjunct, not a replacement for instrumentation.$$, 1),
    (qid, $$C$$, $$is more abrasive, allowing faster removal of calculus deposits$$, false, $$Glycine is less abrasive than bicarbonate, not more; its safety profile comes from lower hardness, not faster cutting.$$, 2),
    (qid, $$D$$, $$cannot be used supragingivally, only subgingivally$$, false, $$Glycine powder can be used both supra- and subgingivally (with a subgingival-rated nozzle); it is not restricted to subgingival use only.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Glycine is a naturally occurring amino acid formulated into a fine, round-particle powder that is
substantially less abrasive than sodium bicarbonate. This lower hardness and smaller particle size
make it safer for subgingival use on root surfaces and around implant/abutment surfaces, where
bicarbonate's coarser, harder crystals can cause excessive substrate loss or surface roughening.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
