    (qid, $$A$$, $$using cooler water in the mix$$, true, NULL, 0),
    (qid, $$B$$, $$using warmer water in the mix$$, false, $$Warmer water speeds the chemical reaction and shortens setting time.$$, 1),
    (qid, $$C$$, $$increasing the powder-to-water ratio$$, false, $$A higher powder-to-water ratio (thicker mix) sets faster than the manufacturer's recommended ratio.$$, 2),
