  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$disinfect it with an EPA-registered intermediate-level disinfectant spray, following manufacturer contact time, before pouring the cast$$, true, NULL, 0),
    (qid, $$B$$, $$pour the cast in dental stone right away without any disinfection step$$, false, $$Skipping disinfection risks transmitting pathogens to the lab/model area.$$, 1),
    (qid, $$C$$, $$let the impression air-dry on the countertop for several hours before disinfecting$$, false, $$Alginate begins to dehydrate ("syneresis") and distort within minutes of air exposure; a multi-hour delay ruins dimensional accuracy regardless of disinfection.$$, 2),
    (qid, $$D$$, $$soak the impression in the disinfectant solution for at least 30 minutes$$, false, $$Prolonged immersion causes alginate to imbibe water (imbibition), distorting the impression; brief spray disinfection is preferred over soaking.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Alginate impressions must be disinfected to break the chain of cross-contamination before they
leave the treatment area, typically with an appropriate spray-and-wrap technique for the
manufacturer-specified contact time, then rinsed again before pouring. Extended immersion is
