  returning id into qid;

  delete from public.options where question_id = qid;
  insert into public.options (question_id, label, body, is_correct, distractor_rationale, sort_order) values
    (qid, $$A$$, $$it can aid bacterial reduction and coagulation within the pocket after scaling and root planing$$, false, $$True statement: adjunctive bacterial reduction and coagulation are documented benefits, so it is not the exception.$$, 0),
    (qid, $$B$$, $$it is used adjunctively, in addition to, not instead of, mechanical debridement$$, false, $$True statement: professional guidance is explicit that laser use is adjunctive, not a replacement for debridement — not the exception.$$, 1),
    (qid, $$C$$, $$it substitutes entirely for hand and ultrasonic instrumentation and removes subgingival calculus on its own$$, true, NULL, 2),
    (qid, $$D$$, $$its effects depend on wavelength, power settings, and proper tissue-contact technique$$, false, $$True statement: laser effects vary by wavelength/power/technique — not the exception.$$, 3);

  insert into public.rationales (question_id, correct_explanation)
  values (qid, $$Soft-tissue diode lasers can supplement nonsurgical periodontal therapy — assisting with bacterial
reduction, pocket decontamination, and hemostasis — but they do not remove calculus and cannot replace
mechanical instrumentation. Effective subgingival debridement still requires hand or ultrasonic
instrumentation; the laser is an adjunct layered on top of it, and its clinical effect varies with
wavelength and operating parameters.$$)
  on conflict (question_id) do update set correct_explanation = excluded.correct_explanation;
end
$do$;

