insert into public.flashcards (slug, taxonomy_id, front, back, status, reference, updated_at)
values ($$fc-anes-0001$$, (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pharmacology$$ and coalesce(subdomain, '') = $$Local Anesthesia$$), $$How is articaine metabolized, and why does it matter?$$, $$Partly hydrolyzed by plasma esterases (it has an ester side chain), unlike other amides that are metabolized in the liver. This gives it a short plasma half-life (~20-30 min) and a lower risk of systemic accumulation.$$, $$approved$$, $$Malamed, Handbook of Local Anesthesia$$, now())
