insert into public.flashcards (slug, taxonomy_id, front, back, status, reference, updated_at)
values ($$fc-anes-0005$$, (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Scientific Basis for Dental Hygiene Practice$$ and coalesce(domain, '') = $$Pharmacology$$ and coalesce(subdomain, '') = $$Local Anesthesia$$), $$Why does buffering a local anesthetic with sodium bicarbonate speed up its onset?$$, $$It raises the solution's pH closer to the drug's pKa, shifting more of the drug into its
uncharged (base) form. The uncharged form crosses the lipid nerve sheath more readily, so the
anesthetic reaches the nerve and takes effect faster (and the injection often stings less).$$, $$approved$$, $$Malamed, Handbook of Local Anesthesia — buffering local anesthetic solutions$$, now())
