insert into public.flashcards (slug, taxonomy_id, front, back, status, reference, updated_at)
values ($$fc-anes-0006$$, (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Dental Hygiene Care Planning$$ and coalesce(subdomain, '') = $$Anxiety and pain control — Local anesthesia$$), $$A patient takes a tricyclic antidepressant. What's the safe approach to using local anesthetic
with epinephrine?$$, $$Standard dental cartridge concentrations of epinephrine (e.g., 1:100,000) are fine with careful
technique — aspirate before injecting and use the lowest effective dose. Tricyclic
antidepressants potentiate epinephrine's pressor effect, so the specific product to avoid is
epinephrine-impregnated gingival retraction cord, which delivers a much higher epinephrine
concentration.$$, $$approved$$, $$Malamed, Handbook of Local Anesthesia — drug interactions with vasoconstrictors$$, now())
