insert into public.flashcards (slug, taxonomy_id, front, back, status, reference, updated_at)
values ($$fc-perio-0002$$, (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Periodontal Disease Management$$ and coalesce(subdomain, '') = $$Prescribed therapy — Chemotherapeutic agents$$), $$What is subantimicrobial-dose doxycycline (SDD) and how does it help periodontal healing?$$, $$A 20 mg twice-daily dose of doxycycline too low to kill bacteria. It works as a host-modulation
agent, inhibiting the host's own matrix metalloproteinases (MMPs) that break down collagen and
bone — used as an adjunct to scaling and root planing, not as an antibiotic.$$, $$approved$$, $$Newman & Carranza, Clinical Periodontology — host modulation therapy$$, now())
