insert into public.flashcards (slug, taxonomy_id, front, back, status, reference, updated_at)
values ($$fc-perio-0003$$, (select id from public.taxonomy where spec_version = $$after_update_2026$$ and area = $$Provision of Clinical Dental Hygiene Services$$ and coalesce(domain, '') = $$Periodontal Disease Management$$ and coalesce(subdomain, '') = $$Prescribed therapy — Implant care$$), $$What is the strongest modifiable risk factor for peri-implantitis, and why does it matter for
maintenance recall?$$, $$Cigarette smoking — it reduces gingival vascularity and impairs the local immune response around
implants, raising peri-implantitis risk. Along with residual pockets and other risk factors, it
argues for a shorter (e.g., 3-month) maintenance recall interval instead of the standard 6 months.$$, $$approved$$, $$Newman & Carranza, Clinical Periodontology — risk factors for peri-implant disease$$, now())
